const PAIRS = [{"pair_id": "apple__apple-scab__cedar-apple-rust", "crop": "Apple", "a": "Apple Scab", "b": "Cedar-Apple Rust", "sign_a": "No tube-like outgrowths; underside shows the same velvety olive-brown fungal growth as the top, no cluster of cups or tubes", "sign_b": "Cluster of small finger-like tubular aecia (cup/tube structures, aecial 'fringe') protruding from the underside directly beneath the orange spot", "shared": "Foliar leaf spotting and fruit blemishing on apple appearing in spring to early summer, both favored by wet weather, both capable of premature leaf drop and downgraded fruit. On young leaves either can begin as small chlorotic or dull flecks before the diagnostic color and texture develop."}, {"pair_id": "apple__black-rot__fire-blight", "crop": "Apple", "a": "Black Rot", "b": "Fire Blight", "sign_a": "No ooze; instead pycnidia (tiny black fungal fruiting bodies) erupt on cankers and mummified fruit", "sign_b": "Sticky bacterial ooze droplets exude from infected shoots, fruitlets, and canker margins under warm humid conditions", "shared": "Brown-to-black necrotic tissue on twigs, leaves, and fruit; cankers on woody parts; rapid death of shoots and spurs; both favored by wounds and can appear in the same orchard during the same warm, wet spring window. Both can produce wilting/blackened shoot tips that lead a scout toward a generic \"twig blight\" call."}, {"pair_id": "blue-spruce__ceropsora-weirii__spruce-needle-rusts", "crop": "Blue Spruce", "a": "Ceropsora Weirii", "b": "Spruce Needle Rusts", "sign_a": "Waxy, blister-like yellow-orange CUSHIONS (pustules) flush with or swelling from the needle surface, releasing yellow-orange spores at budbreak.", "sign_b": "Pale orange to white, elongate TUBE-LIKE or column projections standing up from the needle, shedding powdery orange spores.", "shared": "Orange-to-yellow discoloration and rust-colored, powdery spore masses on Colorado blue spruce needles, with yellowing, browning, and premature needle drop that thins the crown; both worsen in cool, wet weather and typically start on lower/inner foliage before spreading upward via wind-blown spores."}, {"pair_id": "boxwood__boxwood-blight__pseudonectria-buxi-b-o--dodge", "crop": "Boxwood", "a": "Boxwood Blight", "b": "Pseudonectria Buxi B.O. Dodge", "sign_a": "Yes \u2014 sharply defined black or dark-brown linear streaks and lesions on green stems are diagnostic and present", "sign_b": "No true black stem streaking; dieback is associated with stems that were already wounded, winter-injured, or shaded/stressed, lacking the clean black cankers", "shared": "Tan to brown leaf discoloration, leaf spots, leaf drop, and twig/stem dieback on boxwood, with pinkish to salmon/orange fruiting bodies (sporulation) appearing on the surface of infected leaves and stems, often during warm humid weather."}, {"pair_id": "cabbage__bacterial-soft-rot__black-rot-of-crucifers", "crop": "Cabbage", "a": "Bacterial Soft Rot", "b": "Black Rot Of Crucifers", "sign_a": "Veins remain normal-colored; rot is in the soft parenchyma, not confined to the vascular system; cut tissue oozes slimy liquid", "sign_b": "Veins/vascular ring are distinctly blackened or browned (black veins), and bacterial ooze appears from cut vascular bundles; blackening progresses through the vascular system", "shared": "Rotting, water-soaked-to-necrotic tissue on cabbage leaves and head; both can cause head and outer-leaf breakdown, wilting, and an offensive odor in advanced stages; both favored by warm, wet conditions and spread by water, wounds, and handling; both can collapse a head in the field or in storage."}, {"pair_id": "common-bean__common-bacterial--blight-of-beans--fuscous-blight__halo-blight", "crop": "Common Bean", "a": "Common Bacterial  Blight Of Beans, Fuscous Blight", "b": "Halo Blight", "sign_a": "Lesion bordered by a narrow bright-yellow zone (lemon-yellow margin) but NO broad chlorotic halo", "sign_b": "Lesion ringed by a wide greenish-yellow chlorotic HALO of tissue extending well beyond the necrotic center", "shared": "Water-soaked spots on leaves that enlarge and turn brown/necrotic, often coalescing; lesions also appear on pods (sometimes greasy, sunken) and stems; both can ooze bacterial exudate that dries to a crust; both are seed-transmitted and spread by rain-splash and handling of wet foliage, causing blighting, defoliation, and discolored/shriveled seed."}, {"pair_id": "common-bean__dry-bean-rust__halo-blight", "crop": "Common Bean", "a": "Dry Bean Rust", "b": "Halo Blight", "sign_a": "Raised reddish-brown (later black) erumpent pustules that rupture the epidermis and shed rust-colored urediniospores onto fingers/tissue", "sign_b": "Smooth, flat, water-soaked or greasy-looking necrotic spots with no powdery spores; bacterial ooze may exude in humid conditions", "shared": "Scattered small circular leaf lesions, each commonly ringed by a yellow halo, appearing mid-season on bean foliage and capable of causing premature defoliation and yield loss."}, {"pair_id": "corn__anthracnose__gray-leaf-spot", "crop": "Corn", "a": "Anthracnose", "b": "Gray Leaf Spot", "sign_a": "Anthracnose shows black ACERVULI bearing stiff dark SETAE (bristles) and falcate (sickle-shaped, curved) hyaline conidia", "sign_b": "Gray leaf spot shows gray fuzzy CONIDIOPHORES emerging from stomata bearing long, straight, multi-septate Cercospora conidia (no setae)", "shared": "Elongate to oval necrotic lesions on lower/older corn leaves during warm, humid weather, often associated with corn residue from no-till or continuous-corn fields. Both can produce tan-to-brown discoloration with chlorotic margins and both spread upward through the canopy as the season progresses, leading to blighting of leaf tissue and potential yield loss under heavy pressure."}, {"pair_id": "corn__common-corn-rust__gray-leaf-spot", "crop": "Corn", "a": "Common Corn Rust", "b": "Gray Leaf Spot", "sign_a": "Raised, erumpent pustules break through the epidermis and shed cinnamon-brown to rusty-orange powdery urediniospores that rub off on a finger.", "sign_b": "Lesions are flat, embedded in the leaf with an intact surface; nothing powdery rubs off, only a faint gray fungal sporulation visible under high humidity/hand lens.", "shared": "Scattered brown to tan lesions on corn leaf blades, most conspicuous from late vegetative through tasseling/grain fill, capable of coalescing and reducing green leaf area and yield under favorable warm, humid conditions."}, {"pair_id": "corn__common-corn-rust__southern-corn-rust", "crop": "Corn", "a": "Common Corn Rust", "b": "Southern Corn Rust", "sign_a": "Pustules form roughly equally on BOTH upper and lower leaf surfaces", "sign_b": "Pustules form predominantly on the UPPER leaf surface", "shared": "Circular-to-oval raised pustules erupting through the leaf epidermis on corn, ranging from cinnamon-brown to orange, scattered across the leaf surface; both can be present mid-to-late season and both spread via wind-blown urediniospores moving up from southern overwintering regions."}, {"pair_id": "corn__goss--bacterial-wilt__northern-corn-leaf-blight", "crop": "Corn", "a": "Goss' Bacterial Wilt", "b": "Northern Corn Leaf Blight", "sign_a": "Surface shows a glistening, varnish-like sheen of dried bacterial ooze that flakes off; NO spores, even in a humid chamber", "sign_b": "Olive-green to grayish-black dusty fungal sporulation (conidia) develops on lesion surface, especially under high humidity or after incubation", "shared": "Long tan-to-grayish necrotic foliar lesions on corn leaves that develop after canopy closure, can coalesce to blight large portions of the leaf, look water-soaked early, and are promoted by warm, humid/wet weather. Both can cause significant yield loss and premature leaf death, and both lesions tend to elongate down the leaf blade."}, {"pair_id": "cucumber__angular-leaf-spot-of-cucumber__anthracnose", "crop": "Cucumber", "a": "Angular Leaf Spot Of Cucumber", "b": "Anthracnose", "sign_a": "Bacterial exudate: cloudy droplets of ooze on the lower lesion surface that dry to a thin white scale; no fruiting bodies", "sign_b": "Fungal acervuli: black dot-like fruiting structures producing salmon-pink to orange gelatinous spore masses, often in concentric rings", "shared": "Tan-to-brown angular or irregular leaf spots, often vein-delimited, with water-soaked or yellow halos, appearing on cucumber foliage during warm, wet, high-humidity periods; both can progress to leaf tattering and affect fruit."}, {"pair_id": "cucumber__angular-leaf-spot-of-cucumber__corynespora-leaf-spot", "crop": "Cucumber", "a": "Angular Leaf Spot Of Cucumber", "b": "Corynespora Leaf Spot", "sign_a": "Bacterial ooze: water-soaked underside exuding milky droplets that dry to a thin white/tan crust; no fungal growth", "sign_b": "Sparse to moderate olivaceous/dark fungal sporulation (conidiophores bearing long conidia) on the lesion surface, visible with a hand lens, especially lower leaf surface", "shared": "Angular to subcircular tan-to-brown leaf spots on cucumber leaves, often vein-bounded, with yellow halos and eventual shot-holing/tearing of necrotic centers; both worsen under warm humid conditions and can cause significant defoliation."}, {"pair_id": "cucumber__angular-leaf-spot-of-cucumber__cucurbit-downy-mildew", "crop": "Cucumber", "a": "Angular Leaf Spot Of Cucumber", "b": "Cucurbit Downy Mildew", "sign_a": "No fuzzy mold; instead a milky-white bacterial exudate that dries to a thin white crust/flake on the underside of water-soaked spots", "sign_b": "A grayish to purplish-black downy fungal mat (sporangiophores) on the lower leaf surface within the lesion", "shared": "Angular, vein-limited lesions on the foliage of cucumber that begin as small water-soaked spots, expand to a polygonal shape constrained by major veins, then turn yellow and brown/necrotic. Both diseases are driven by free moisture (rain, overhead irrigation, dew) and cool-to-moderate temperatures, both can defoliate plants under heavy pressure, and both reduce yield and fruit quality."}, {"pair_id": "cucumber__anthracnose__corynespora-leaf-spot", "crop": "Cucumber", "a": "Anthracnose", "b": "Corynespora Leaf Spot", "sign_a": "Acervuli with dark setae and salmon-colored masses of curved/cylindrical hyaline conidia (Colletotrichum); slimy spore ooze in moist conditions.", "sign_b": "Sparse gray-olive tufts of erect conidiophores bearing large, multi-septate (pseudoseptate), obclavate Corynespora conidia\u2014no setae, no salmon ooze.", "shared": "Circular to angular tan/brown necrotic leaf spots, often 5-15 mm, that may show concentric or chlorotic halos and coalesce into large blighted areas causing premature defoliation on cucumber foliage during warm humid weather."}, {"pair_id": "cucumber__anthracnose__cucurbit-downy-mildew", "crop": "Cucumber", "a": "Anthracnose", "b": "Cucurbit Downy Mildew", "sign_a": "Pink to salmon-orange gelatinous spore masses (acervuli with setae) form, especially on fruit and stem lesions; no downy growth", "sign_b": "A fuzzy gray-to-purple downy sporulation (sporangiophores) develops on the lower leaf surface directly beneath the angular spot", "shared": "Early-season chlorotic to tan/brown foliar spots on cucumber leaves that can coalesce, cause leaf blighting and defoliation, and reduce yield. From a distance both can look like a generalized leaf spot/blight, especially in warm, wet, humid weather with leaf wetness favoring both pathogens."}, {"pair_id": "cucumber__anthracnose__gummy-stem-blight", "crop": "Cucumber", "a": "Anthracnose", "b": "Gummy Stem Blight", "sign_a": "Stem lesions bear acervuli (often with setae) and salmon spore ooze; no copious amber gummy exudate from the stem", "sign_b": "Stem canker exudes characteristic reddish-brown to amber gummy beads and is studded with black pycnidia (and pseudothecia)", "shared": "Circular to angular tan/brown necrotic leaf lesions that may coalesce, dark pycnidia/acervuli within lesions, water-soaked margins early, stem cankers, and fruit rot. Both favor warm, humid, rainy weather and spread by splashing rain/overhead irrigation, and both survive in residue and on cucurbit seed."}, {"pair_id": "cucumber__anthracnose__phytophthora-blight", "crop": "Cucumber", "a": "Anthracnose", "b": "Phytophthora Blight", "sign_a": "Sunken lesion produces salmon-to-pink, gelatinous spore masses (acervuli with sticky conidia), often in concentric rings, in the center of the sunken spot.", "sign_b": "Lesion is covered by a white, dense, powdery/cottony mold (sporangiophores and sporangia) like a 'powdered-sugar' or yeast-like bloom, especially on fruit on wet soil.", "shared": "Sunken, water-soaked lesions on cucumber fruit plus leaf spotting and vine/runner dieback; both worsen in warm, wet weather and can rot fruit in the field or in transit."}, {"pair_id": "cucumber__anthracnose__powdery-mildew", "crop": "Cucumber", "a": "Anthracnose", "b": "Powdery Mildew", "sign_a": "No surface powder; tissue shows defined necrotic lesions, signs are within/on the dead tissue (acervuli), not a wipeable coating", "sign_b": "White-to-gray powdery, talc-like fungal growth on the leaf surface that smears when rubbed", "shared": "Both affect cucumber foliage during the main growing season, can cause leaves to appear discolored, blotchy, or to decline and die, and reduce canopy and yield. From a distance an infected leaf with pale patches and dead tissue can be hard to assign without a hand-lens look at the lesion surface and margins."}, {"pair_id": "cucumber__anthracnose__pythium-diseases", "crop": "Cucumber", "a": "Anthracnose", "b": "Pythium Diseases", "sign_a": "Sunken circular lesions bearing salmon-pink to orange spore masses (acervuli) in concentric rings; gelatinous pink ooze", "sign_b": "Soft watery rot with no colored spore masses; under high humidity a white cottony cobweb-like mycelium grows over the surface", "shared": "Water-soaked, sunken, soft to firm rotting lesions on cucumber tissue, especially fruit resting on wet soil, with rapid expansion in warm, humid/rainy weather. Both can cause tissue collapse and secondary rot, and both are favored by extended leaf/fruit wetness and overhead irrigation."}, {"pair_id": "cucumber__bacterial-wilt__phytophthora-blight", "crop": "Cucumber", "a": "Bacterial Wilt", "b": "Phytophthora Blight", "sign_a": "Viscous, milky-white bacterial ooze pulls into fine sticky threads when cut stem ends are separated (positive 'string test'); cucumber beetles often present", "sign_b": "No ooze strands; instead crown and lower stem show dark water-soaked soft rot, and fruit on or near the soil bears white cottony/powdery sporulation", "shared": "Rapid wilting of runners or the whole plant, often during warm summer weather, with green-to-flagging foliage that collapses; affected plants may die quickly and appear scattered or in patches across the field."}, {"pair_id": "cucumber__corynespora-leaf-spot__cucurbit-downy-mildew", "crop": "Cucumber", "a": "Corynespora Leaf Spot", "b": "Cucurbit Downy Mildew", "sign_a": "Underside shows a sparse, fuzzy olive-gray to brown to black mold (Corynespora conidiophores bearing long obclavate multi-septate conidia), present on either surface and not strictly confined to lesion outline", "sign_b": "Underside shows a delicate gray-purple to dark downy fuzz (Pseudoperonospora sporangiophores with lemon-shaped sporangia) confined precisely to the angular lesion beneath the yellow upper-surface spot", "shared": "Angular to irregular chlorotic spots on cucumber leaves, often vein-delimited, beginning on older/lower leaves and progressing upward; spots coalesce into large necrotic blighted areas that can defoliate the plant under warm, humid, high-leaf-wetness conditions in greenhouse or field."}, {"pair_id": "cucumber__cucurbit-downy-mildew__gummy-stem-blight", "crop": "Cucumber", "a": "Cucurbit Downy Mildew", "b": "Gummy Stem Blight", "sign_a": "Fuzzy gray-to-purple downy sporulation (sporangiophores) on the lower leaf surface under dew/humidity", "sign_b": "No downy growth; instead tiny black pycnidia/perithecia dotting tan lesions and stem cankers, sometimes exuding amber gummy ooze", "shared": "Yellow to brown leaf lesions on a cucumber canopy progressing to widespread foliar blighting and defoliation, often appearing mid-season under warm humid conditions, with the potential for rapid loss of the vine and sunscald of exposed fruit."}, {"pair_id": "cucumber__cucurbit-downy-mildew__phytophthora-blight", "crop": "Cucumber", "a": "Cucurbit Downy Mildew", "b": "Phytophthora Blight", "sign_a": "Fine downy gray-to-purple sporulation (sporangiophores) on the LEAF UNDERSIDE within angular lesions in humid morning conditions", "sign_b": "No leaf-underside downy fuzz; instead white cottony/powdery sporangia on rotting fruit, crown, or stem lesions at the soil line", "shared": "Sudden water-soaked tissue and foliar collapse on cucumber during hot, humid, wet weather; both spread explosively after rain and can defoliate or kill plants quickly, giving a general impression of a fast-moving wet rot/blight."}, {"pair_id": "cucumber__cucurbit-downy-mildew__powdery-mildew", "crop": "Cucumber", "a": "Cucurbit Downy Mildew", "b": "Powdery Mildew", "sign_a": "Gray-to-violet downy sporangial growth on the LOWER leaf surface only, beneath the chlorotic spot", "sign_b": "White-to-gray powdery, talc-like fungal growth on the UPPER (and eventually both) leaf surface that rubs off", "shared": "Yellow to chlorotic patches on mature cucurbit leaves, leaf bronzing/necrosis, premature defoliation, and reduced fruit quality. Both spread rapidly in dense canopies and are favored by humidity, so early symptomatic leaves can appear similar from the top of the canopy."}, {"pair_id": "cucumber__gummy-stem-blight__phytophthora-blight", "crop": "Cucumber", "a": "Gummy Stem Blight", "b": "Phytophthora Blight", "sign_a": "Amber/reddish-brown gummy exudate beads from stem cankers; tiny black pycnidia and perithecia (speckling) stud the tan tissue", "sign_b": "White, cottony, downy sporangial growth on the lesion surface under humid conditions; NO gum and NO black pycnidia; tissue is water-soaked", "shared": "Warm-season cucurbit collapse: water-soaked stem and crown lesions, fruit rot, and rapid wilting of vines after periods of high humidity, rain, or overhead irrigation. Both can girdle the stem and kill plants, and both attack fruit in contact with wet soil or splashed by rain."}, {"pair_id": "cucumber__phytophthora-blight__pythium-diseases", "crop": "Cucumber", "a": "Phytophthora Blight", "b": "Pythium Diseases", "sign_a": "Dense white, powdery-to-cottony yeast-like growth covering the fruit surface; lemon-shaped (papillate) caducous sporangia of P. capsici on short stalks", "sign_b": "Sparse, fine white cottony mycelium; non-papillate sporangia and characteristic Pythium oospores/sporangia, no dense powdery fruit bloom", "shared": "Wilting, collapse, and crown/root rot of cucumber plants in wet, low spots of the field; water-soaked soft rot of fruit resting on saturated soil; seedling damping-off in cool wet or overwatered conditions; both favored by heavy rain, ponding, irrigation, and warm-to-moderate soil moisture; both are oomycetes with motile zoospores spread by splashing and surface water."}, {"pair_id": "cucumber__phytophthora-blight__rhizoctonia-damping-off--blight-and-rot", "crop": "Cucumber", "a": "Phytophthora Blight", "b": "Rhizoctonia Damping-Off, Blight And Rot", "sign_a": "A dense white, powdery to yeasty-looking cottony growth (sporangia) coats the rotting fruit/crown; in water it releases motile zoospores \u2014 an oomycete water mold.", "sign_b": "Coarse, brown to tan web-like mycelial strands (and occasionally brown sclerotia) on the lesion; never any white powdery bloom and no swimming spores \u2014 a true fungus.", "shared": "Sudden seedling collapse with stem lesions at or near the soil line, wilting/dying plants in patches, and rotting fruit in contact with the soil \u2014 symptoms that look identical until you examine the lesion texture, sporulation, and the soil-moisture context."}, {"pair_id": "cucumber__pythium-diseases__rhizoctonia-damping-off--blight-and-rot", "crop": "Cucumber", "a": "Pythium Diseases", "b": "Rhizoctonia Damping-Off, Blight And Rot", "sign_a": "No visible aerial mycelium on the lesion; if cultured, produces fine non-septate hyphae and (in water) swimming zoospores/oospores; lesion looks bare and watery", "sign_b": "Coarse, brown, right-angle-branched septate mycelium with constrictions at branch points visible on the lesion/soil surface; brown hyphal webbing binds soil particles to the stem", "shared": "Poor or patchy stand establishment with pre- and post-emergence damping-off of cucumber seedlings, water-soaked stem constrictions near the soil line, toppled or wilted plants, and rotting of roots/lower stem; both worsen in heavy, compacted, or poorly drained seedbeds and can also rot fruit in contact with soil."}, {"pair_id": "cultivated-garlic__gray-molds__white-rot", "crop": "Cultivated Garlic", "a": "Gray Molds", "b": "White Rot", "sign_a": "Larger, flat, irregular BLACK sclerotia (1-5+ mm) embedded among gray mold, plus abundant gray spores.", "sign_b": "Numerous TINY round poppy-seed-like black sclerotia (about 0.5 mm, sand-grain sized) crusting the basal plate and roots in the white mycelium.", "shared": "Yellowing and dieback of leaves from the tips, premature collapse of the plant, and a soft to semi-watery rot of the bulb and neck/basal plate accompanied by white fungal mycelium. Both favor cool, moist conditions and can continue to destroy bulbs in storage or in the field, leaving the cloves decayed and the plant easily lifted from loosened roots."}, {"pair_id": "dogwood__dogwood-anthracnose__powdery-mildew", "crop": "Dogwood", "a": "Dogwood Anthracnose", "b": "Powdery Mildew", "sign_a": "No powdery coating; symptoms are necrotic tissue with no removable surface growth (at most tiny dark fruiting bodies within dead tissue).", "sign_b": "White, powdery, cobwebby mycelium dusts the leaf surface and shoot tips, wiping off and leaving green/yellowed tissue beneath; classic powdery mildew sign.", "shared": "Distorted, discolored dogwood leaves with marginal scorch, blotches, and premature leaf drop; both more common on plants in shaded, humid, poorly ventilated sites and both can affect new shoots, giving overlapping early-summer foliar symptoms."}, {"pair_id": "douglas-fir__rhabdocline-needlecasts__swiss-needle-cast", "crop": "Douglas-Fir", "a": "Rhabdocline Needlecasts", "b": "Swiss Needle Cast", "sign_a": "Fruiting bodies (apothecia) are reddish-brown to dark, elongate elliptical, and rupture through the needle surface, NOT confined to the stomatal lines", "sign_b": "Two parallel rows of tiny black, spherical pseudothecia emerge precisely from the white stomatal lines (stomata) on the needle underside", "shared": "Discolored (yellow-green to brown) needles on Douglas-fir, premature shedding of older needles leaving only the current-year needles, thinning crowns, and reduced vigor. Both worsen on stressed trees, become most visible in spring, and are economically important on Christmas-tree and timber plantations."}, {"pair_id": "eggplant__diaporthe-vexans-gratz__phytophthora-blight", "crop": "Eggplant", "a": "Diaporthe Vexans Gratz", "b": "Phytophthora Blight", "sign_a": "Numerous tiny black pycnidia (pimple-like fruiting bodies) embedded in the lesion, often in concentric rings, exuding cream/amber spore tendrils (cirrhi) when moist; no white fuzzy growth.", "sign_b": "White, cottony to powdery sporangial growth (mold) over the lesion surface under humid conditions; no embedded black pycnidia, no dry tendrils.", "shared": "Dark, sunken to spreading lesions on fruit, leaf spotting, and stem cankers/dieback during warm, humid weather, with both capable of causing rapid fruit rot and plant collapse in the field and in storage/transit."}, {"pair_id": "grape__black-rot__grape-anthracnose", "crop": "Grape", "a": "Black Rot", "b": "Grape Anthracnose", "sign_a": "Black rot shows abundant well-defined, evenly spaced black globose pycnidia erupting through the surface (mummies and leaf spots studded with them).", "sign_b": "Anthracnose lesions lack neat globose pycnidia; in wet conditions they ooze a creamy/pinkish acervulus-borne conidial mass from the sunken gray center.", "shared": "Small circular reddish to reddish-brown spots on young grape leaves, dark depressed lesions on green shoots/canes, and circular spots on green berries that darken and shrink, all developing during warm wet spring/early-summer weather on new-season tissue."}, {"pair_id": "grape__black-rot__gray-mold", "crop": "Grape", "a": "Black Rot", "b": "Gray Mold", "sign_a": "Black Rot mummies are hard, black, and coal-like, densely studded with raised black pycnidia (and later pseudothecia); no fuzzy growth.", "sign_b": "Gray Mold berries are covered with a conspicuous powdery/fuzzy gray-brown mat of mycelium and conidiophores ('gray mold') that puffs into dust when disturbed.", "shared": "Both diseases attack ripening grape clusters, cause berries to brown and rot, and ultimately leave shriveled, dried-out (mummified) berries on the rachis. Each thrives in wet, humid conditions and can devastate a cluster, so an isolated view of rotting/dried berries late in the season is easily confused."}, {"pair_id": "grape__downy-mildew__powdery-mildew", "crop": "Grape", "a": "Downy Mildew", "b": "Powdery Mildew", "sign_a": "White-to-grayish DOWNY, cottony sporulation confined to the LOWER (abaxial) leaf surface, directly beneath yellow upper-surface 'oilspots'", "sign_b": "White-to-gray POWDERY, dusty/talc-like growth that can occur on EITHER surface (often upper) and rubs off easily", "shared": "Pale/chlorotic to discolored patches on leaves, whitish fungal growth visible on foliage and developing berries, distortion and drop of infected leaves, and reduced fruit set or rotted/cracked berries late season. Both thrive in the growing season and can defoliate vines and downgrade fruit quality."}, {"pair_id": "highbush-blueberry__anthracnose__phomopsis-cankers-and-twig-blights", "crop": "Highbush Blueberry", "a": "Anthracnose", "b": "Phomopsis Cankers And Twig Blights", "sign_a": "Salmon to orange, gelatinous spore masses (acervuli) ooze from infected fruit and lesions in wet conditions \u2014 Colletotrichum", "sign_b": "Small black, embedded flask-shaped pycnidia stud the dead bark/twig, exuding cream-colored spore tendrils when wet \u2014 Phomopsis", "shared": "Wilting, browning, and dieback of one-year-old shoots/twigs in spring, plus a soft rot of ripening and harvested berries. Both overwinter in dead wood/mummified tissue, spread by rain-splashed conidia in warm wet weather, and cause economic loss mainly as post-harvest fruit rot. From a distance, a bush with scattered dead flagging shoots and some rotting fruit could be either."}, {"pair_id": "highbush-blueberry__anthracnose__twig-canker", "crop": "Highbush Blueberry", "a": "Anthracnose", "b": "Twig Canker", "sign_a": "Salmon-pink to orange gelatinous spore masses (acervuli oozing conidia) on fruit and lesions in humid conditions", "sign_b": "Black, roughened, raised fruiting bodies (perithecia/stroma of Gibbera) embedded in the canker surface; no orange ooze", "shared": "Dark sunken lesions and dieback on blueberry twigs/canes, leading to wilting of distal foliage and loss of fruiting wood, often noticed during or after winter on weakened or stressed bushes."}, {"pair_id": "highbush-blueberry__mummy-berry__phomopsis-cankers-and-twig-blights", "crop": "Highbush Blueberry", "a": "Mummy Berry", "b": "Phomopsis Cankers And Twig Blights", "sign_a": "Brown trumpet-shaped apothecia (mushroom cups) emerge in spring from mummified berries on the soil surface; conidia on blighted shoots smell to attract insects and mimic flowers", "sign_b": "Pycnidia (tiny black flask-shaped fruiting bodies) embedded in canker/dead bark and dead twigs; no apothecia and no ground mummies", "shared": "Spring blighting and wilting of young succulent shoots, with browning and dieback of new growth and flowers; both can cause shoots to suddenly droop and turn brown (\"shepherd's crook\" or flagging), and both may infect through blossoms, leading to confusion during the bloom-to-early-fruit window."}, {"pair_id": "highbush-blueberry__mummy-berry__twig-canker", "crop": "Highbush Blueberry", "a": "Mummy Berry", "b": "Twig Canker", "sign_a": "Hard gray/tan mummified berries on the soil that in spring produce small mushroom-like, cup-shaped apothecia (trumpet stage); conidia give a gray bloom on blighted shoots", "sign_b": "No mummified fruit; instead small black flask-shaped fruiting bodies (perithecia) erupting through the bark on the dead cankered twig surface", "shared": "Brown, wilting, dying young shoots/twigs and associated leaf browning in spring, giving a shepherd's-crook or flagging dieback appearance on scattered stems."}, {"pair_id": "hosta__hosta-virus-x__tobacco-rattle-virus", "crop": "Hosta", "a": "Hosta Virus X", "b": "Tobacco Rattle Virus", "sign_a": "Positive for Potexvirus Hosta virus X antigen/RNA on a HVX-specific immunostrip or RT-PCR; negative for tobravirus", "sign_b": "Positive for Tobacco rattle virus (Tobravirus) by ELISA/RT-PCR; negative on HVX immunostrip", "shared": "Mottled, blotchy, or color-broken hosta foliage with chlorotic-to-necrotic patterning, tissue-collapse or \"puckered\" areas, and no visible pathogen structures (no spores, mildew, or fruiting bodies). Both are graft/mechanically and (for TRV) nematode/vegetatively transmitted, systemic, and incurable\u2014infected plants must be rogued. Both lack any sign vector you can see with a hand lens, so diagnosis rests on the pattern and distribution of symptoms plus the typical transmission context."}, {"pair_id": "juniper__diaporthe-juniperivora-sacc__kabatina-blight", "crop": "Juniper", "a": "Diaporthe Juniperivora Sacc.", "b": "Kabatina Blight", "sign_a": "New, succulent spring/summer growth blights progressively through the growing season; tips first turn dull green, then reddish-brown, then ash-gray, and disease keeps spreading in warm wet weather", "sign_b": "Damage appears as last year's (1-year-old) shoots that are found already dead/dull-brown in late winter to early spring (Feb-Apr); current succulent new growth is NOT attacked", "shared": "Scattered dead, ash-gray to reddish-brown twig tips on juniper (especially eastern redcedar and ornamental Juniperus/Chamaecyparis), with a definite girdling lesion/canker at the junction of dead and living tissue, tiny black fruiting bodies erupting on the killed bark, and a tendency to be worse on dense, young nursery stock and lower/inner crown."}, {"pair_id": "juniper__kabatina-blight__phomopsis-cankers-and-twig-blights", "crop": "Juniper", "a": "Kabatina Blight", "b": "Phomopsis Cankers And Twig Blights", "sign_a": "One-year-old wood (previous season's growth) is girdled and killed; the current-season tip beyond may remain, dieback is of older shoot segments", "sign_b": "Current-season succulent new growth and tips are killed; youngest, tender shoots blight first", "shared": "Dieback of juniper twig tips; foliage turns dull green to yellow then reddish-brown and finally ash-gray, with a distinct lesion/canker marking the boundary between dead and healthy wood. Small black fruiting bodies (pycnidia) erupt through the bark/scales of the killed tissue. Both are most severe on stressed or wounded plants and favor moist conditions."}, {"pair_id": "lettuce__downy-mildew__gray-mold", "crop": "Lettuce", "a": "Downy Mildew", "b": "Gray Mold", "sign_a": "Dichotomously branched, tree-like sporangiophores bearing hyaline sporangia (downy mildew of an oomycete); no sclerotia", "sign_b": "Grape-like clusters of conidia on branched gray conidiophores; hard black sclerotia may form on/in rotted tissue", "shared": "On head and leaf lettuce in cool, humid, or wet weather: yellowing of outer/lower leaves progressing to tan-brown necrotic patches, leaf collapse, and a fuzzy mold on affected tissue. Both can rot outer wrapper leaves and cause field and postharvest losses, and both flourish under prolonged leaf wetness, dense canopies, and dew."}, {"pair_id": "lettuce__downy-mildew__powdery-mildew", "crop": "Lettuce", "a": "Downy Mildew", "b": "Powdery Mildew", "sign_a": "Fluffy, downy, gray-white sporulation (tree-like sporangiophores) confined beneath the angular lesions", "sign_b": "Dry, white, powdery, dusty mycelial mat that can be rubbed off, spread superficially over the surface", "shared": "Pale to yellow patches on lettuce leaves accompanied by a whitish/grayish surface bloom, progressing to leaf yellowing, browning, and reduced marketability, typically on older/outer wrapper leaves first."}, {"pair_id": "lettuce__gray-mold__sclerotinia-stem-rot", "crop": "Lettuce", "a": "Gray Mold", "b": "Sclerotinia Stem Rot", "sign_a": "Fuzzy, dusty GRAY to gray-brown sporulating mold (conidiophores) coating the surface; puffs of spores when disturbed", "sign_b": "Dense, fluffy, cottony WHITE mycelium with no gray dusty sporulation", "shared": "Mature head and romaine lettuce in cool (15-20C), wet/humid conditions develops a soft, watery, brown decay at the crown, basal stem, and lower wrapper leaves at or near the soil line. Affected plants wilt, the outer leaves collapse, and the head can rot down and flatten onto the soil. Both pathogens overwinter as sclerotia in soil and crop debris and both are favored by dense canopies, splashing/free moisture, and lettuce grown on the same ground repeatedly."}, {"pair_id": "lettuce__gray-mold__sclerotinia-timber-rot", "crop": "Lettuce", "a": "Gray Mold", "b": "Sclerotinia Timber Rot", "sign_a": "No true sclerotia within tissue; at most small flat black stromatic crusts late, but the hallmark is gray conidial dust, not embedded black bodies.", "sign_b": "Hard, irregular BLACK sclerotia (rat-dropping sized, 2-10 mm) form on and inside the white mycelium and within hollowed stems/crown \u2014 the definitive sign.", "shared": "A lettuce plant (often at heading to near-harvest maturity) wilts and collapses, with a soft, watery brown rot of the crown, lower leaves, and stem/basal tissue in contact with cool, moist soil. White fungal mycelium is visible at the lesion margin near the soil line, and infected heads slump and decay."}, {"pair_id": "lettuce__rhizoctonia-damping-off--blight-and-rot__southern-blight", "crop": "Lettuce", "a": "Rhizoctonia Damping-Off, Blight And Rot", "b": "Southern Blight", "sign_a": "Coarse brown web-like mycelium and brown sclerotia that are irregular, the same brown color as mycelium, embedded in tissue and lacking a distinct rind", "sign_b": "Abundant white fan-like (cottony) mycelium radiating over the crown and adjacent soil, bearing numerous uniform tan-brown spherical sclerotia the size of mustard seeds", "shared": "Wilting and collapse of lettuce plants, brown to reddish-brown sunken lesions on the lower stem/crown and basal leaves at or near the soil line, decay of wrapper/bottom leaves leading to head rot, favored by warm soil and present in damping-off of seedlings as well as rot of mature heads."}, {"pair_id": "lettuce__sclerotinia-stem-rot__sclerotinia-timber-rot", "crop": "Lettuce", "a": "Sclerotinia Stem Rot", "b": "Sclerotinia Timber Rot", "sign_a": "Numerous, very small (about 0.5-2 mm), irregular poppy-seed-like black sclerotia, often abundant on and within tissue and in soil", "sign_b": "Fewer, large (about 3-10+ mm), elongated or irregular black sclerotia, often formed in the pith of the hollowed stem", "shared": "Sudden wilt and collapse of the lettuce head, water-soaked tan-to-brown soft rot at the crown and lower stem/leaf bases, white cottony (fluffy) mycelial growth on affected tissue under moist conditions, and the eventual formation of hard black sclerotia in or on the rotted tissue. Both progress to complete plant collapse (\"drop\") and thrive in cool, wet, dense canopy conditions."}, {"pair_id": "lettuce__sclerotinia-stem-rot__southern-blight", "crop": "Lettuce", "a": "Sclerotinia Stem Rot", "b": "Southern Blight", "sign_a": "Numerous small, irregular, poppy-seed-sized black sclerotia (~0.5-2 mm), embedded in the white mycelium", "sign_b": "Round, uniform, tan-to-reddish-brown sclerotia resembling mustard/cabbage seeds (~1-3 mm), turning brown with age, scattered on mycelium and soil surface", "shared": "Wilting and collapse of the lettuce head, soft watery rot of the crown and lower stem at the soil line, and white cottony mycelial growth on affected tissue. Both cause plants to flag and die in patches, leaving slimy, decayed basal tissue, and both survive in soil as sclerotia."}, {"pair_id": "lettuce__sclerotinia-timber-rot__southern-blight", "crop": "Lettuce", "a": "Sclerotinia Timber Rot", "b": "Southern Blight", "sign_a": "Large, irregular, black sclerotia 2-10+ mm (pea-to-bean sized), formed inside and on the stem/tissue", "sign_b": "Numerous tiny, uniform, round sclerotia 0.5-2 mm that mature from white/cream to tan/reddish-brown like mustard seeds", "shared": "A maturing lettuce plant wilts and the whole head collapses; the lower stem and outer wrapper leaves at the soil line turn into a soft, watery, brown rot. White cottony fungal growth appears on affected tissue and on the adjacent soil, and small hard fungal resting bodies (sclerotia) form in or on the decayed tissue. Often appears in patches in the field, especially in cool/warm moist conditions near harvest."}, {"pair_id": "maple__anthracnose__tar-spot-of-maple", "crop": "Maple", "a": "Anthracnose", "b": "Tar Spot Of Maple", "sign_a": "Lesions are flat to slightly sunken necrotic tissue, dull and papery, flush with the leaf surface.", "sign_b": "Mature spot is a distinctly RAISED, glossy, wavy/furrowed black stroma 5-15 mm across that looks like a drop of dried tar sitting on the leaf.", "shared": "Dark brown-to-black foliar spots/blotches on maple leaves during the growing season, both fungal, both non-lethal/cosmetic, both overwintering in leaf litter and spread by spring rain-splashed spores."}, {"pair_id": "melon__alternaria-leaf-blight__cucurbit-downy-mildew", "crop": "Melon", "a": "Alternaria Leaf Blight", "b": "Cucurbit Downy Mildew", "sign_a": "Sparse dark olive-brown to black powdery/velvety mold (conidia) on top or underside of necrotic tissue, no fuzzy down", "sign_b": "Fine grayish-purple to dark downy (felty) sporulation in a layer on the underside beneath each angular yellow spot", "shared": "Yellow to chlorotic foliar spots on older leaves first, progressing to brown necrosis, leaf blighting, premature defoliation, and reduced fruit quality (sunscald, poor sugar). Both favor warm, wet, humid weather with extended leaf wetness and both spread by wind and rain-splash through the canopy."}, {"pair_id": "melon__alternaria-leaf-blight__gummy-stem-blight", "crop": "Melon", "a": "Alternaria Leaf Blight", "b": "Gummy Stem Blight", "sign_a": "No stem gumming; on leaves, signs are sooty olive-brown conidiophores/conidia (large muriform Alternaria spores) on lesion surface, never an amber stem ooze", "sign_b": "Reddish-amber gummy ooze exudes from stem cankers; black pycnidia (and pseudothecia) studded in stem and crown tissue release spores; diagnostic gummy droplets", "shared": "Circular to angular tan-brown necrotic leaf spots with concentric rings and yellow halos, beginning on older crown leaves, coalescing into large blighted areas with progressive defoliation that exposes fruit to sunscald; both favor warm, wet, humid weather and dense canopies, and both produce tiny dark fungal fruiting structures in lesions detectable with magnification."}, {"pair_id": "melon__anthracnose__bacterial-fruit-blotch", "crop": "Melon", "a": "Anthracnose", "b": "Bacterial Fruit Blotch", "sign_a": "Black fruiting bodies (acervuli) with dark setae, exuding salmon-to-pink, gelatinous spore masses (conidia in slime)", "sign_b": "No fungal structures; pressed cut lesion yields cloudy bacterial streaming/ooze and a milky exudate, rind surface beaded with droplets", "shared": "Dark, sunken or water-soaked lesions on the upper fruit surface plus angular-to-irregular necrotic leaf spots on a warm-season cucurbit; both worsen with rain, overhead irrigation, and dense canopy, and both can rot fruit before or at harvest."}, {"pair_id": "melon__anthracnose__cucurbit-downy-mildew", "crop": "Melon", "a": "Anthracnose", "b": "Cucurbit Downy Mildew", "sign_a": "Under wet conditions lesions/fruit produce salmon-to-pink, gelatinous acervuli (slimy spore masses); no fuzzy mold, no purple-gray down", "sign_b": "On the lower leaf surface beneath the angular spot there is a fine purple-gray to black downy fungal-like growth (sporangiophores), best seen at dawn under high humidity", "shared": "Angular-to-irregular chlorotic and necrotic foliar lesions on melon leaves during warm, wet/humid weather, with progressive leaf yellowing, browning, and eventual blighting/defoliation of the canopy; both favor leaf wetness and can rapidly spread across a field."}, {"pair_id": "melon__anthracnose__gummy-stem-blight", "crop": "Melon", "a": "Anthracnose", "b": "Gummy Stem Blight", "sign_a": "No amber gummy exudate; stem lesions are dry, elongate, tan-to-brown without a beaded resin", "sign_b": "Reddish-brown to amber gummy ooze (gummosis) beads from the cracked stem canker, often at nodes", "shared": "Tan-to-brown necrotic leaf spots that enlarge, coalesce, and cause leaf blighting; stem lesions/cankers; sunken fruit rot lesions; and tiny dark embedded fruiting bodies (pepper-spot speckling) in killed tissue. Both favor warm, wet/humid conditions and spread by splashing rain and overhead irrigation."}, {"pair_id": "melon__bacterial-fruit-blotch__cucurbit-downy-mildew", "crop": "Melon", "a": "Bacterial Fruit Blotch", "b": "Cucurbit Downy Mildew", "sign_a": "No fungal growth; a milky bacterial ooze streams from cut tissue in water (positive bacterial streaming)", "sign_b": "Fuzzy gray-to-purple downy sporulation (sporangiophores) on the lower leaf surface within the angular lesion", "shared": "Angular, water-soaked to dark brown foliar lesions bounded by leaf veins, appearing during warm wet weather and spreading quickly through a field, sometimes with a yellow halo and eventual leaf necrosis."}, {"pair_id": "melon__bacterial-fruit-blotch__gummy-stem-blight", "crop": "Melon", "a": "Bacterial Fruit Blotch", "b": "Gummy Stem Blight", "sign_a": "Cut tissue placed in clear water shows milky bacterial streaming; lesions are bacterial with water-soaked margins and amber ooze, no fungal fruiting bodies", "sign_b": "Lesion surface bears numerous tiny black pycnidia/perithecia (specks) and the cracked stem oozes a reddish-brown to amber GUMMY exudate; microscopy shows fungal spores", "shared": "Dark, often water-soaked leaf spots and necrotic fruit lesions on melon during warm, humid, rainy weather; both cause damping-off/seedling blight from infected seed or splash, and both can rot maturing fruit in the field, producing irregular dark blotches."}, {"pair_id": "melon__bacterial-fruit-blotch__phytophthora-blight", "crop": "Melon", "a": "Bacterial Fruit Blotch", "b": "Phytophthora Blight", "sign_a": "Sticky amber-to-cream bacterial ooze/streaming from cracks; no mold; bacterial streaming visible under microscope from cut tissue in water", "sign_b": "Dense white, cottony sporangial mold (sugary/powdered-sugar look) on the fruit surface under high humidity", "shared": "Water-soaked, expanding lesions on melon fruit and foliage in hot, humid/rainy conditions, leading to fruit rot and potential crop loss; both favored by overhead irrigation, splashing rain, and warm temperatures, and both can collapse fruit quickly once established."}, {"pair_id": "melon__bacterial-wilt__charcoal-rot", "crop": "Melon", "a": "Bacterial Wilt", "b": "Charcoal Rot", "sign_a": "Sticky, milky-white bacterial ooze strings out between the two cut ends (positive ooze test)", "sign_b": "No bacterial ooze; instead pith/vascular tissue is peppered with tiny black specks (microsclerotia) giving a charcoal-dusted appearance", "shared": "A melon plant or individual runner that flags and wilts, often abruptly, with leaves first drooping during the heat of the day and eventually dying. Both can kill plants from mid-season into fruiting, both are favored by warm temperatures, and in both the foliage may remain green-to-tan and clinging as the vine collapses, so the aboveground picture (a wilting, dying, but not obviously rotted plant) looks nearly identical."}, {"pair_id": "melon__bacterial-wilt__fusarium-wilts--blights--rots-and-damping-off", "crop": "Melon", "a": "Bacterial Wilt", "b": "Fusarium Wilts, Blights, Rots And Damping-Off", "sign_a": "Viscous white-to-clear bacterial strands stretch and string out between the cut stem halves (positive 'ooze string test')", "sign_b": "No stringing ooze; cut surface may be dry, with internal vascular browning instead", "shared": "Sudden or progressive wilting of melon vines with initially green (not yet chlorotic) leaves, drooping runners, and eventual plant death. Both can affect plants from seedling through fruiting stages and produce a generalized loss of turgor that mimics drought stress."}, {"pair_id": "melon__bacterial-wilt__phytophthora-blight", "crop": "Melon", "a": "Bacterial Wilt", "b": "Phytophthora Blight", "sign_a": "Viscous, white-to-clear bacterial slime strings between the cut stem ends (positive ooze/string test), confirming Erwinia in the xylem", "sign_b": "No bacterial stringing; cut tissue is rotted/water-soaked or firm with no ooze (string test negative)", "shared": "Sudden, dramatic wilting and collapse of melon vines, often starting with individual runners and progressing to whole-plant death; can appear midseason on otherwise healthy-looking plants and be mistaken for drought stress or generic vine decline."}, {"pair_id": "melon__charcoal-rot__fusarium-wilts--blights--rots-and-damping-off", "crop": "Melon", "a": "Charcoal Rot", "b": "Fusarium Wilts, Blights, Rots And Damping-Off", "sign_a": "Abundant tiny (pinpoint, ~0.1mm) jet-black microsclerotia peppered through and on the gray tissue, giving a 'charcoal'/sooty speckled appearance", "sign_b": "No black specks; salmon-pink to white fungal mycelium/sporodochia on the surface under humidity, with brown vascular streaking", "shared": "Mid- to late-season melon plants showing progressive wilting, yellowing/decline of vines, and eventual collapse; cutting the lower stem or crown reveals internal vascular/cortical discoloration, and affected roots/crowns show rot. Both favor stressed plants and warm soils, and both can be mistaken for drought or other vine-decline complexes."}, {"pair_id": "melon__charcoal-rot__gummy-stem-blight", "crop": "Melon", "a": "Charcoal Rot", "b": "Gummy Stem Blight", "sign_a": "Tiny, smooth, jet-black MICROSCLEROTIA (uniform pepper-grain bodies) peppering gray stem and root tissue; no cellular pycnidia, no spore ooze.", "sign_b": "Dark PYCNIDIA (flask-shaped fruiting bodies with ostioles) embedded in tan tissue, exuding cream-to-amber spore tendrils (cirrhi) when wet.", "shared": "Mid- to late-season melon plants showing wilting, vine decline, and crown/stem cankers, frequently coinciding with fruit set and heat stress. Affected stems show tan-to-brown lesions near the soil line or at nodes, dark speckling within the lesion, and eventual girdling that collapses the runner or whole plant. Both diseases can leave a dry, shredded or split stem and are commonly lumped together as \"sudden wilt\" or \"vine decline.\""}, {"pair_id": "melon__cucurbit-downy-mildew__gummy-stem-blight", "crop": "Melon", "a": "Cucurbit Downy Mildew", "b": "Gummy Stem Blight", "sign_a": "Fine downy grayish-to-purple sporulation (sporangiophores) on the lower leaf surface within the angular lesion", "sign_b": "No downy growth; instead small dark pinpoint pycnidia (and sometimes oozing tendrils) embedded in tan lesions and especially in stem cankers", "shared": "Yellow to brown angular or irregular leaf lesions, progressive leaf necrosis and canopy blighting, and decline of vining melon plants during warm, humid, wet weather; both spread quickly across a field and can defoliate plants, exposing fruit to sunscald."}, {"pair_id": "melon__cucurbit-downy-mildew__powdery-mildew", "crop": "Melon", "a": "Cucurbit Downy Mildew", "b": "Powdery Mildew", "sign_a": "Sparse gray-to-purple/violet downy sporulation (sporangiophores) in humid conditions, hard to rub off", "sign_b": "Dense white-to-tan talc-like powder (conidial chains) that wipes off readily with a finger", "shared": "Yellowing/chlorotic blotches on melon (cucurbit) leaves with a visible \"mildew\" growth and progressive leaf decline that can defoliate the canopy and reduce fruit quality. At a glance both produce yellow patches and a whitish-to-grayish coating, leading to confusion in the field."}, {"pair_id": "melon__fusarium-wilts--blights--rots-and-damping-off__gummy-stem-blight", "crop": "Melon", "a": "Fusarium Wilts, Blights, Rots And Damping-Off", "b": "Gummy Stem Blight", "sign_a": "No black pycnidia; in humid conditions whitish to pink mycelial/sporodochial growth (Fusarium) may appear on the surface of cut, rotting tissue, and vascular streaks are tan/brown", "sign_b": "Numerous minute black pycnidia (and later perithecia) embedded in tan-to-bleached cankers on the stem, leaves and crown, giving a peppered appearance", "shared": "Wilting, declining or collapsing melon vines, often appearing near flowering/fruit set; stem lesions/cankers at or near the crown; amber gum exudate possible from cracked stem tissue; seedling damping-off; internal stem/vascular discoloration; reduced vigor and possible whole-plant death in patches across the field."}, {"pair_id": "melon__fusarium-wilts--blights--rots-and-damping-off__monosporascus-root-rot", "crop": "Melon", "a": "Fusarium Wilts, Blights, Rots And Damping-Off", "b": "Monosporascus Root Rot", "sign_a": "Pinkish/white to salmon mycelium or sporodochia on stem/crown lesions; no embedded black flask-shaped fruiting bodies on roots", "sign_b": "Tiny black, ball-like perithecia (cleistothecia) embedded in the surface of rotted roots, visible with a hand lens", "shared": "Mature melon vines wilt and decline, frequently around fruit load, with yellowing and necrosis of foliage progressing to plant collapse and yield loss. Both pathogens are soilborne, favored by stressed or weakened root systems, and produce symptoms that first appear as patchy or scattered plant decline within the field."}, {"pair_id": "melon__fusarium-wilts--blights--rots-and-damping-off__phytophthora-blight", "crop": "Melon", "a": "Fusarium Wilts, Blights, Rots And Damping-Off", "b": "Phytophthora Blight", "sign_a": "Continuous reddish-brown to chocolate vascular (xylem) discoloration streaking up the stem from the roots, with internal tissue otherwise intact (a true vascular wilt)", "sign_b": "Brown, water-soaked soft rot of the cortex and pith with NO confined vascular streak; under humidity the surface produces white sporangial growth (water mold) rather than vascular browning", "shared": "Wilting and collapse of melon plants, seedling damping-off, crown and root rot, and rot of fruit in contact with soil. Both can kill plants rapidly and both are favored by warm soils, so a field showing scattered to patchy wilting with rotted lower stems looks similar at first glance."}, {"pair_id": "melon__gummy-stem-blight__phytophthora-blight", "crop": "Melon", "a": "Gummy Stem Blight", "b": "Phytophthora Blight", "sign_a": "Dark, globose pycnidia/perithecia embedded in tissue, exuding hyaline conidia in tendrils; no white aerial sporangia", "sign_b": "White, branched, cottony sporangiophores bearing lemon-shaped (papillate) sporangia; motile zoospores release in free water", "shared": "Wilting, collapsing melon plants with darkened, necrotic lesions on the lower stem/crown, foliar blighting, and fruit rot, often appearing in warm, wet weather and capable of killing plants outright."}, {"pair_id": "oak__anthracnose__leaf-spot", "crop": "Oak", "a": "Anthracnose", "b": "Leaf Spot", "sign_a": "Discula/Apiognomonia produces acervuli (cushion-like masses) oozing cream-colored conidia, typically along veins on the lower leaf surface; no shield-shaped structures.", "sign_b": "Tubakia dryina produces distinctive dark, shield-like (peltate) pycnothyria/sporodochia on a central stalk, visible as tiny dark dots, releasing one- to few-celled conidia.", "shared": "Irregular brown-to-tan necrotic leaf blotches on oak, frequently expanding along or between major veins, with potential for premature leaf drop. Lesions can be papery and coalesce, and both diseases are promoted by prolonged leaf wetness and dense canopies. Casual inspection of a single symptomatic leaf does not separate them."}, {"pair_id": "oak__anthracnose__oak-wilt", "crop": "Oak", "a": "Anthracnose", "b": "Oak Wilt", "sign_a": "Tiny dark fungal fruiting bodies (acervuli) on dead vein tissue of leaves; NO vascular streaking in sapwood", "sign_b": "Brown/black streaking or discoloration in the outer sapwood (xylem) of wilting branches; pressure pads/fungal mats may form under bark with a fruity odor", "shared": "Discolored/browning oak leaves with premature leaf drop in spring through early summer, often alarming the observer into thinking the tree is dying."}, {"pair_id": "oak__bacterial-leaf-scorch__leaf-spot", "crop": "Oak", "a": "Bacterial Leaf Scorch", "b": "Leaf Spot", "sign_a": "No fungal signs; tissue is sterile to the lens because the cause is a xylem-limited bacterium (Xylella) not visible without lab assay (ELISA/PCR)", "sign_b": "Tiny black pinhead fruiting bodies (pycnothyria of Tubakia) visible in the spots, confirming a fungal cause", "shared": "Brown, dead leaf tissue on oak (especially red oak group) appearing in mid-to-late summer, often most visible July-September, with leaves looking \"scorched\" and premature canopy decline. Both can be associated with hot, dry, or stressful summer conditions and both affect the foliage of the same hosts."}, {"pair_id": "oak__bacterial-leaf-scorch__oak-wilt", "crop": "Oak", "a": "Bacterial Leaf Scorch", "b": "Oak Wilt", "sign_a": "No fungal mats; xylem may show little or no discrete brown streaking; only a lab xylem assay (PCR/ELISA) detects the bacterium", "sign_b": "Brown/black streaking or discoloration in the outer sapwood (especially in red oaks); fungal pressure pads/mats may form under the bark, sometimes cracking it, with a sweet fruity odor", "shared": "Mature oaks showing marginal/interveinal leaf browning (\"scorch\"), thinning canopy, and progressive branch dieback during summer. Both are xylem/vascular diseases that disrupt water movement, so foliage looks drought-stressed even with adequate soil moisture. Early symptoms on both can appear on a single branch or one side of the crown before generalizing, making them easy to confuse at a distance."}, {"pair_id": "oak__botryosphaeria-rots-and-cankers__oak-wilt", "crop": "Oak", "a": "Botryosphaeria Rots And Cankers", "b": "Oak Wilt", "sign_a": "Discoloration is confined to and radiates from the localized canker; sapwood streaking does not run continuously as a systemic ring toward the root system", "sign_b": "Continuous brown/black streaking in the outermost sapwood (current ring) running systemically through branches toward the trunk and root grafts", "shared": "A mature oak showing dieback with browning, wilting leaves and discolored sapwood streaking in symptomatic branches; dead twigs and branches in the crown with reduced vigor."}, {"pair_id": "oak__ganoderma-root-and-butt-rot__oak-wilt", "crop": "Oak", "a": "Ganoderma Root And Butt Rot", "b": "Oak Wilt", "sign_a": "Shelf-like to hoof-shaped polypore conk at the base/roots\u2014shiny reddish-brown varnished cap (G. lucidum) with white pore surface; white rot of basal wood", "sign_b": "No basal conk; instead dark vascular streaking in outer sapwood and gray-to-black fungal mats under bark that crack it (cracks/pressure pads), insect/root-graft spread", "shared": "Mature oak in slow-to-moderate decline with crown thinning, branch dieback from the top/outer canopy inward, reduced vigor, and ultimately tree death. Both can produce sparse, undersized, or off-color foliage and may affect high-value landscape and forest oaks, prompting concern about whether the tree is hazardous or salvageable."}, {"pair_id": "oak__leaf-spot__oak-wilt", "crop": "Oak", "a": "Leaf Spot", "b": "Oak Wilt", "sign_a": "Sapwood is clean and white; no vascular streaking; no fruiting mat under bark", "sign_b": "Brown to greenish-black vascular streaking in the outer sapwood, and in red oaks fragrant fungal pressure pads/mats forming under and cracking the bark", "shared": "Brown to dark discoloration of oak leaves with premature defoliation appearing in mid-to-late summer; both can show leaf necrosis and leaf drop and both affect oaks (often red oak group), prompting concern about a \"dying\" tree."}, {"pair_id": "peach__botryosphaeria-canker--white-rot__brown-rot", "crop": "Peach", "a": "Botryosphaeria Canker, White Rot", "b": "Brown Rot", "sign_a": "Sparse, dark, embedded pycnidia (pimple-like flask-shaped fruiting bodies) that ooze a creamy/white spore mass; sporulation is dull, not powdery, and not in concentric rings", "sign_b": "Abundant powdery, tan-to-gray tufts of conidia (sporodochia) erupting in concentric rings over the lesion surface, giving a fuzzy, ash-gray sporulating mass", "shared": "A circular, expanding brown/tan rotted area on a maturing or ripe peach fruit, often firm at first, sometimes with the fungus fruiting on the surface; both pathogens overwinter on the tree (in cankers/mummies) and gain entry through wounds, insect injury, or growth cracks, and both are favored by warm, wet, humid summer weather as harvest approaches."}, {"pair_id": "peanut__nothopassalora-personata__passalora-fungus", "crop": "Peanut", "a": "Nothopassalora Personata", "b": "Passalora Fungus", "sign_a": "Dark sporulation predominantly on the ABAXIAL (lower) surface, with conidiophores in concentric rings/tufts (rosettes) giving a velvety dark appearance; conidia dark olivaceous-brown", "sign_b": "Sporulation predominantly on the ADAXIAL (upper) surface; conidiophores lighter, not in tight concentric rosettes; conidia hyaline to pale, longer and more tapered", "shared": "Subcircular necrotic leaf spots (2-10 mm) on peanut leaflets, petioles, and stems, progressing to coalescence, premature defoliation, and yield loss. Both intensify with warm, humid, frequently wet foliage conditions and overlap in mid-to-late season, so a single dark spot on a leaflet does not by itself separate them."}, {"pair_id": "peony__anthracnose__botrytis-blight", "crop": "Peony", "a": "Anthracnose", "b": "Botrytis Blight", "sign_a": "Salmon-pink to orange slimy spore masses (conidia in acervuli), sometimes with tiny black setae/dots in the lesion center", "sign_b": "Fuzzy gray-brown mold (botrytis 'gray mold') covering rotted buds/stems; in older tissue hard black sclerotia embedded in pith", "shared": "Brown to reddish-brown necrotic lesions on leaves, petioles, and stems; bud and shoot blight with collapse of young growth; both worsen in cool, wet, humid spring weather and on crowded plantings with poor air circulation; both can girdle stems causing wilt of the tissue above."}, {"pair_id": "pepper__bacterial-spot__tomato-spotted-wilt-virus", "crop": "Pepper", "a": "Bacterial Spot", "b": "Tomato Spotted Wilt Virus", "sign_a": "Cut lesion margin placed in water shows bacterial streaming/ooze under hand lens or microscope; lesion centers may dry and tear (shot-hole); negative for TSWV in immunostrip", "sign_b": "No bacterial streaming from lesions; TSWV lateral-flow immunostrip/ELISA positive; ringspots are sterile necrosis", "shared": "Dark necrotic leaf spots (often with chlorotic halos or ring patterns), foliar yellowing and premature leaf drop, stunted plants, and distorted/discolored fruit with surface blemishes. Both can appear scattered across the canopy on field and greenhouse pepper."}, {"pair_id": "phlox__downy-mildew__powdery-mildew", "crop": "Phlox", "a": "Downy Mildew", "b": "Powdery Mildew", "sign_a": "Grayish-white to bluish-purple downy/fuzzy growth confined to the UNDER surface of the leaf", "sign_b": "White-to-gray powdery, dusty, talc-like coating mostly on the UPPER surface (and stems/buds)", "shared": "Mid- to late-season foliar disease on garden phlox (Phlox paniculata) with discolored, declining leaves and a mildew-like growth that gardeners describe simply as \"mildew on the phlox.\" Lower and interior leaves are often affected first, foliage may yellow, brown, and drop, and both diseases reduce vigor and bloom in dense, poorly ventilated plantings."}, {"pair_id": "potato__bacterial-soft-rot__late-blight", "crop": "Potato", "a": "Bacterial Soft Rot", "b": "Late Blight", "sign_a": "No fungal-like growth on leaves; soft rot is bacterial and produces no surface sporulation, only ooze and slime on rotting tissue", "sign_b": "A delicate white-to-grayish downy/fuzzy sporulation ring at the margin of leaf lesions on the underside, visible especially after dew or high humidity", "shared": "Water-soaked, dark, rapidly spreading lesions on tubers and/or lower stems; wet decay of internal tuber tissue; field plants showing collapsing, darkened stems and a generally wet, rotting appearance in humid or wet conditions."}, {"pair_id": "potato__bacterial-soft-rot__phytophthora-root-and-stem-rot", "crop": "Potato", "a": "Bacterial Soft Rot", "b": "Phytophthora Root And Stem Rot", "sign_a": "No distinctive color change; tissue is cream to tan, slimy and structureless, with sharp demarcation but no pink/red reaction", "sign_b": "Cut tissue turns salmon-pink to brick-red within ~20-30 min of air exposure, then darkens to brown/black (the classic 'pink rot' reaction)", "shared": "Wilting, lower-stem/crown decay, and a soft, watery breakdown of belowground tissue. Affected tubers become mushy and discolored; aboveground plants wilt and may collapse. Both are favored by wet, poorly drained, waterlogged soils and warm-to-moderate temperatures, and both progress rapidly in storage."}, {"pair_id": "potato__bacterial-soft-rot__rhizoctonia-damping-off--blight-and-rot", "crop": "Potato", "a": "Bacterial Soft Rot", "b": "Rhizoctonia Damping-Off, Blight And Rot", "sign_a": "No sclerotia; tuber surface clean or slimy, decay is internal maceration with bacterial ooze", "sign_b": "Black, hard, irregular sclerotia (black scurf) firmly stuck to tuber skin that cannot be washed off; white mycelial mat in humid conditions", "shared": "Rotting/decaying potato tissue below or near the soil line: pre-emergence sprout death, stem girdling/cankers, and tuber breakdown, often in cool, wet, poorly drained soil, leading to gappy stands and reduced vigor."}, {"pair_id": "potato__late-blight__tomato-spotted-wilt-virus", "crop": "Potato", "a": "Late Blight", "b": "Tomato Spotted Wilt Virus", "sign_a": "White, downy sporangiophore growth ('white mold ring') at the lesion edge on the underside of the leaf, especially in cool wet weather", "sign_b": "No fungal/oomycete sporulation ever; lesions stay dry. Thrips (vector) may be found in growing points", "shared": "Dark necrotic to chlorotic foliar lesions with associated leaf death, stem involvement, possible wilting/collapse of shoots, and internal tuber discoloration/necrosis that can lead a grower to suspect a single foliar \"blight\" complex."}, {"pair_id": "potato__phytophthora-root-and-stem-rot__rhizoctonia-damping-off--blight-and-rot", "crop": "Potato", "a": "Phytophthora Root And Stem Rot", "b": "Rhizoctonia Damping-Off, Blight And Rot", "sign_a": "Internal tissue is a wet, spongy rot; freshly cut tissue exposed to air develops a salmon-pink to reddish tinge that darkens to brown/black; no surface sclerotia", "sign_b": "Hard, dark brown-to-black sclerotia (black scurf, looks like soil that won't wash off) adhere to stem base and tuber surface; cankers are dry, sunken, reddish-brown", "shared": "Stunted, wilting potato plants with discolored, rotting underground stems and stolons; reduced emergence or post-emergence collapse in cool, wet soils; affected stems girdled below the soil line leading to chlorosis and decline of the canopy."}, {"pair_id": "red-pine__diplodia-sapinea-de-not__sirococcus-blight-of-conifers", "crop": "Red Pine", "a": "Diplodia Sapinea De Not.", "b": "Sirococcus Blight Of Conifers", "sign_a": "Conidia large, oblong-ellipsoid, thick-walled, dark brown, mostly aseptate (rarely 1-septate), roughly 30-45 x 10-16 um", "sign_b": "Conidia small, hyaline to pale, two-celled (1-septate) with unequal cells, club/spindle-shaped, roughly 12-18 x 3-6 um", "shared": "Brown, killed current-year shoots and needles on red pine, often with a sharp transition from healthy to dead tissue, resin exudation at the base of blighted shoots, shoot tips bending or drooping, and tiny black fruiting structures (pycnidia) emerging on dead needles, shoots, or cone scales. Damage concentrates on the new flush and lower/interior crown, and both can cause repeated annual tip dieback."}, {"pair_id": "soybean__bacterial-blight__bacterial-pustule-of-soybean-disease", "crop": "Soybean", "a": "Bacterial Blight", "b": "Bacterial Pustule Of Soybean Disease", "sign_a": "No pustule; lesion is flat, water-soaked, angular, often with a translucent margin and a visible bacterial exudate that dries shiny", "sign_b": "A small raised pale/tan pustule (erumpent volcano-like blister) present in the center of the spot on the underside of the leaf", "shared": "Small water-soaked to angular leaf spots on soybean foliage, often with yellow-green chlorotic halos, that enlarge and coalesce; lesion centers turn brown and may tear/drop out giving a ragged, tattered leaf appearance. Both are bacterial, seedborne, splash-dispersed, favored by wet conditions, and concentrate on upper/younger leaves."}, {"pair_id": "soybean__bacterial-blight__frogeye-leaf-spot", "crop": "Soybean", "a": "Bacterial Blight", "b": "Frogeye Leaf Spot", "sign_a": "No fungal growth; center remains dull, dry necrotic tissue with no fuzz or specks (bacterium produces no visible signs)", "sign_b": "Gray center bears tufts of dark conidiophores/conidia (Cercospora sojina), giving a faint velvety or speckled appearance under magnification", "shared": "Small (1-5 mm) necrotic leaf spots with a pale tan-to-gray center and a darker margin, often with a yellowish halo, distributed on upper canopy leaves of vegetative-to-reproductive soybean."}, {"pair_id": "soybean__bacterial-blight__septoria-leaf-spot", "crop": "Soybean", "a": "Bacterial Blight", "b": "Septoria Leaf Spot", "sign_a": "No fruiting bodies; centers are clean necrotic tissue. Cut margin may exude bacterial ooze in a water mount (streaming test)", "sign_b": "Tiny dark brown-black pinprick pycnidia embedded in the tan lesion centers, exuding cirri of spores under moisture", "shared": "Small brown-to-dark angular/irregular leaf spots, frequently with a yellow halo, that enlarge and coalesce into larger necrotic blotches and can cause tattering or premature defoliation. Both favor wet conditions and can co-occur on the same plant, making leaf-level distinction difficult at a glance."}, {"pair_id": "soybean__bacterial-blight__soybean-rust", "crop": "Soybean", "a": "Bacterial Blight", "b": "Soybean Rust", "sign_a": "No fungal structures; only necrotic/water-soaked tissue, sometimes with a glistening bacterial ooze or papery dried exudate on the underside", "sign_b": "Raised tan-to-reddish-brown volcano-like uredinia (pustules) that rupture and release masses of dusty urediniospores", "shared": "Small foliar lesions on soybean leaflets, initially angular to irregular, often with a chlorotic (yellow) halo and a tan-to-brown necrotic center, that can coalesce, cause leaf tattering/blighting, and trigger premature defoliation under favorable moisture."}, {"pair_id": "soybean__bacterial-blight__soybean-vein-necrosis-virus", "crop": "Soybean", "a": "Bacterial Blight", "b": "Soybean Vein Necrosis Virus", "sign_a": "Bacterial streaming from a cut lesion in water under microscope and/or positive for Pseudomonas savastanoi pv. glycinea; no virus detected", "sign_b": "No bacterial ooze; positive RT-PCR/ELISA for Soybean vein necrosis virus (Orthotospovirus), with Neohydatothrips variabilis thrips present", "shared": "Foliar necrotic lesions on soybean leaflets, frequently in the upper/younger canopy, with necrosis that can follow or sit adjacent to veins. Neither produces visible fungal fruiting structures or spore masses, both can be associated with chlorosis/yellowing around affected tissue, and both can appear scattered across a field rather than in a tight focus."}, {"pair_id": "soybean__bacterial-pustule-of-soybean-disease__downy-mildew", "crop": "Soybean", "a": "Bacterial Pustule Of Soybean Disease", "b": "Downy Mildew", "sign_a": "A small raised, erumpent PUSTULE (volcano-like bump) at the lesion center on the lower surface, with NO mold, fuzz, or spores; pustule is dry and may rupture.", "sign_b": "A downy, fuzzy patch of gray, grayish-violet to purple SPORULATION (tufts of fungal growth) covering the lower surface beneath the chlorotic spot, especially in dew/humid mornings.", "shared": "Small foliar lesions on soybean leaflets appearing as pale-green to yellow chlorotic flecks or angular spots, often a few millimeters across, that later turn tan to brown and may coalesce; both occur during the vegetative-to-reproductive canopy, are favored by warm-to-moist conditions, and can cause a peppered or mottled appearance of the upper leaf surface that prompts confusion."}, {"pair_id": "soybean__bacterial-pustule-of-soybean-disease__frogeye-leaf-spot", "crop": "Soybean", "a": "Bacterial Pustule Of Soybean Disease", "b": "Frogeye Leaf Spot", "sign_a": "Raised pale pustule (blister-like) erupting from lower leaf surface, no fungal threads; pustule center may show a tiny tan crater, frequently bacterial", "sign_b": "Velvety gray fungal sporulation visible in the lesion center, especially on the underside under humidity; tufts of conidiophores, no raised pustule", "shared": "Small, scattered tan-to-brown foliar lesions on soybean leaflets, often appearing mid-to-late season on the upper canopy, sometimes with a yellow halo, that can give leaves a speckled or spotty appearance and cause premature defoliation when severe."}, {"pair_id": "soybean__bacterial-pustule-of-soybean-disease__septoria-leaf-spot", "crop": "Soybean", "a": "Bacterial Pustule Of Soybean Disease", "b": "Septoria Leaf Spot", "sign_a": "Center of the pustule is a bacterial eruption (no fruiting bodies); a milky bacterial ooze may stream from a cut lesion held in water", "sign_b": "Tiny dark brown-to-black pinpoint fungal pycnidia are embedded in the tan lesion center; no bacterial ooze", "shared": "Small angular-to-irregular brown/tan leaf spots, 1-3 mm, often with a yellowish halo, that can coalesce; both cause premature defoliation in severe cases and both are favored by warm, wet/humid conditions and frequent rainfall during the growing season."}, {"pair_id": "soybean__bacterial-pustule-of-soybean-disease__soybean-rust", "crop": "Soybean", "a": "Bacterial Pustule Of Soybean Disease", "b": "Soybean Rust", "sign_a": "No spores; the pustule center is a small erupted bacterial mass, sometimes with bacterial ooze under moisture, and the raised tissue is plant-derived with no powdery discharge.", "sign_b": "Rupturing the uredinium releases abundant dry, tan-to-cinnamon urediniospores (a clear powdery spore mass), confirming a fungal sign.", "shared": "Small angular-to-rounded raised lesions on the foliage of soybean during mid-to-late season, often beginning on lower/middle canopy leaves under warm, humid conditions. Both can produce a peppered appearance of many tiny pustule-like spots and lead to premature defoliation when severe, and both are most conspicuous on the abaxial (lower) leaf surface."}, {"pair_id": "soybean__bacterial-pustule-of-soybean-disease__soybean-vein-necrosis-virus", "crop": "Soybean", "a": "Bacterial Pustule Of Soybean Disease", "b": "Soybean Vein Necrosis Virus", "sign_a": "A small raised PUSTULE (volcano-like) erupts on the underside center of the lesion, no ooze, scrapes to reveal a tan crater; no insect vector", "sign_b": "No pustule whatsoever; surface stays flat with reddish-brown vein necrosis; thrips (the Tospovirus vector) may be present feeding", "shared": "Scattered chlorotic-to-necrotic foliar lesions on upper-canopy trifoliolate leaflets appearing mid-to-late season (R-stages), often with yellow halos and patches that can follow or surround veins, eventually turning brown and causing premature leaf necrosis or defoliation."}, {"pair_id": "soybean__bean-pod-mottle-virus__septoria-leaf-spot", "crop": "Soybean", "a": "Bean Pod Mottle Virus", "b": "Septoria Leaf Spot", "sign_a": "No fungal signs at all; associated with bean leaf beetle feeding/transmission (chewing damage may be present)", "sign_b": "Dark pinpoint pycnidia visible within necrotic spots; no insect vector required, spreads by rain-splashed spores", "shared": "Yellow-green discoloration of soybean foliage with chlorotic and mottled leaf tissue, sometimes accompanied by reduced plant vigor; both are commonly noticed during vegetative-to-early-reproductive stages and can give leaves a blotchy, uneven coloration when scouted from a distance."}, {"pair_id": "soybean__cercospora-blight__frogeye-leaf-spot", "crop": "Soybean", "a": "Cercospora Blight", "b": "Frogeye Leaf Spot", "sign_a": "Lesions, when present, are irregular, angular, reddish-purple blotches without a sharply demarcated pale center", "sign_b": "Lesion has a distinctive 'frogeye' bullseye: gray-to-tan necrotic center surrounded by a dark reddish-brown to purple ring", "shared": "Both are Cercospora-induced foliar diseases of soybean producing leaf spots/discoloration, both favor warm humid weather, both sporulate on lesions, both can affect upper-canopy leaves during reproductive stages, and both are reported across the same soybean-growing regions. Early small lesions of either can look similar before diagnostic features emerge."}, {"pair_id": "soybean__cercospora-blight__soybean-vein-necrosis-virus", "crop": "Soybean", "a": "Cercospora Blight", "b": "Soybean Vein Necrosis Virus", "sign_a": "Fungal sign: dark Cercospora conidiophores and long multiseptate conidia on tissue; pathogen culturable; reddish cercosporin pigment present", "sign_b": "No fungal structures; thrips-vectored tospovirus confirmed only by RT-PCR/ELISA serology - vein-necrosis virus particles, not a culturable organism", "shared": "Upper-canopy soybean leaves develop a bronze to reddish-purple cast progressing to interveinal/vein-associated necrosis during late reproductive stages (R5-R6), with affected leaflets becoming leathery and ultimately dropping; both lack obvious visible fruiting bodies."}, {"pair_id": "soybean__charcoal-rot__genus-diaporthe", "crop": "Soybean", "a": "Charcoal Rot", "b": "Genus Diaporthe", "sign_a": "Innumerable, dust-like, uniformly tiny black microsclerotia peppered densely in the pith and vascular tissue, giving a gray-black 'ground pepper' appearance when the stem is split", "sign_b": "Larger, discrete black flask-shaped perithecia (or pycnidia) embedded in/erupting from the epidermis, often in linear rows on the stem surface, sometimes with cirri (spore tendrils) when wet", "shared": "Premature foliar wilting and chlorosis advancing to brown, dead leaves that remain attached to the plant; reduced vigor and yield; internal vascular/pith discoloration when the stem is split; tiny black specks on the surface of dead lower stem and root tissue. Both typically appear from R3 onward and are favored by plant stress."}, {"pair_id": "soybean__charcoal-rot__root-and-stem-rot", "crop": "Soybean", "a": "Charcoal Rot", "b": "Root And Stem Rot", "sign_a": "Abundant minute black microsclerotia pepper the gray vascular and pith tissue, giving a dusty charcoal-gray appearance", "sign_b": "No microsclerotia present; tissue is brown and rotted with no peppered black specks (oospores not visible to naked eye)", "shared": "Patchy wilting, stunting, premature yellowing/death of plants during reproductive stages, with rot and discoloration of the lower stem and root system; affected plants often retain dead leaves attached, and dieback can occur in pockets within the field."}, {"pair_id": "soybean__downy-mildew__septoria-leaf-spot", "crop": "Soybean", "a": "Downy Mildew", "b": "Septoria Leaf Spot", "sign_a": "A downy fuzzy tuft of gray to pale-violet sporulation (sporangiophores) directly under the chlorotic spot in humid conditions", "sign_b": "No downy growth; surface is dry with tiny dark-brown to black pinpoint pycnidia embedded in the lesion (visible with a hand lens)", "shared": "Spotted soybean leaves during vegetative-to-reproductive growth, with chlorotic to brown lesions scattered across the leaflet that can coalesce and, in heavy cases, cause premature yellowing and defoliation. Both are favored by wet, humid conditions and both can appear on the same plant."}, {"pair_id": "soybean__downy-mildew__soybean-rust", "crop": "Soybean", "a": "Downy Mildew", "b": "Soybean Rust", "sign_a": "Cottony, downy white-to-pale-gray tufts of mold (sporangiophores) carpeting the undersurface, wiping off easily", "sign_b": "Discrete raised volcano-like pustules (uredinia), tan to reddish-brown, that erupt through the epidermis and release powdery urediniospores", "shared": "Pale green to yellow flecks and angular-to-irregular chlorotic spots on the upper leaf surface, with sporulation concentrated on the abaxial (lower) surface directly beneath the lesions; heavy infection causes coalescing lesions, leaf yellowing, and premature defoliation, most evident on mid-to-lower canopy leaves during humid weather."}, {"pair_id": "soybean__downy-mildew__soybean-vein-necrosis-virus", "crop": "Soybean", "a": "Downy Mildew", "b": "Soybean Vein Necrosis Virus", "sign_a": "Pale gray to purplish downy fungal growth (sporangiophores/sporangia) on the LOWER leaf surface directly beneath the chlorotic spots", "sign_b": "No fungal growth on the underside; lesions are dry with no fuzz, only discoloration and possible necrosis", "shared": "Scattered pale-green to yellow chlorotic blotches on upper canopy leaves that can appear angular or vein-delimited, often noticed during R-stage scouting and easily mistaken for one another at a glance."}, {"pair_id": "soybean__genus-diaporthe__root-and-stem-rot", "crop": "Soybean", "a": "Genus Diaporthe", "b": "Root And Stem Rot", "sign_a": "Tiny black pycnidia/perithecia (sometimes in rows or with beaks) emerge from dead stem tissue and pods/seed \u2014 a fungal sign.", "sign_b": "No fruiting bodies form; Phytophthora is an oomycete producing only microscopic oospores/zoospores in tissue, nothing visible erupting from the surface.", "shared": "Soybean plants showing brown stem discoloration, wilting, premature death, and stand loss. Both can scatter dead plants through a field and produce a brown internal/external stem lesion, leading to confusion between an aerial fungal canker and a soil-borne oomycete root/stem rot."}, {"pair_id": "soybean__genus-diaporthe__sclerotinia-timber-rot", "crop": "Soybean", "a": "Genus Diaporthe", "b": "Sclerotinia Timber Rot", "sign_a": "Numerous minute black pycnidia, often in linear rows on dead stems and pod sutures, firmly embedded in the epidermis (scrape with a fingernail and they stay).", "sign_b": "Large (2-10 mm) irregular hard black sclerotia, easily dislodged, found loose inside the hollowed stem pith and on the surface.", "shared": "Scattered or patchy dead/wilting plants in the canopy from flowering through pod fill, with bleached tan-to-gray dead stems standing among green plants, premature death, reduced pod set, and dark fungal fruiting bodies associated with the stem."}, {"pair_id": "soybean__genus-diaporthe__southern-blight", "crop": "Soybean", "a": "Genus Diaporthe", "b": "Southern Blight", "sign_a": "Absent \u2014 no round tan/brown sclerotia; only flask-shaped black fruiting bodies embedded in tissue", "sign_b": "Present \u2014 numerous spherical sclerotia (~1-3 mm) starting white then maturing to tan/reddish-brown like mustard seeds on the white mat", "shared": "Wilting, yellowing, and death of individual soybean plants, frequently in patches, with discolored/lesioned lower stems near the soil line and light-colored fungal growth visible on or around the stem base during warm, humid conditions; both can kill plants prematurely from mid-season onward."}, {"pair_id": "soybean__genus-diaporthe__taproot-decline-on-soybean", "crop": "Soybean", "a": "Genus Diaporthe", "b": "Taproot Decline On Soybean", "sign_a": "Pith may be gray near the canker but the taproot interior is essentially normal in color with NO white mycelial mat", "sign_b": "Taproot/lower stem is black, dry and brittle and the inner pith is packed with robust white mycelium", "shared": "Reproductive-stage (R3-R6) soybean plants showing interveinal chlorosis progressing to necrosis, premature death with leaves often retained, lower-stem/root discoloration, and black fungal structures on the lower stem or root surface."}, {"pair_id": "soybean__root-and-stem-rot__sclerotinia-timber-rot", "crop": "Soybean", "a": "Root And Stem Rot", "b": "Sclerotinia Timber Rot", "sign_a": "No fungal growth; internal stem and root tissue is brown and rotted with no white mold or hard black bodies", "sign_b": "Fluffy white cottony mycelium on stem surface and hard black sclerotia (resembling rat droppings) inside the pith or on the stem", "shared": "Wilting, dying soybean plants occurring in patches with stem rot/discoloration and eventual plant death; both can cause stand loss and are associated with cool, wet conditions and poorly drained or dense areas of the field."}, {"pair_id": "soybean__sclerotinia-timber-rot__southern-blight", "crop": "Soybean", "a": "Sclerotinia Timber Rot", "b": "Southern Blight", "sign_a": "Large (3-10+ mm), irregular, black, rat-dropping-shaped sclerotia formed INSIDE the hollowed pith and on the stem surface", "sign_b": "Numerous tiny (0.5-2 mm), uniform, round, tan-to-reddish-brown sclerotia resembling mustard seeds, formed ON the surface of stem base and surrounding soil/debris", "shared": "Wilting and dying soybean plants, often in patches, bearing white cottony/fluffy mycelium on the lower-to-mid stem along with hardened fungal survival structures (sclerotia), leading to stem girdling and plant death."}, {"pair_id": "soybean__septoria-leaf-spot__soybean-rust", "crop": "Soybean", "a": "Septoria Leaf Spot", "b": "Soybean Rust", "sign_a": "No pustules; the underside shows only flat brown necrotic tissue, sometimes with tiny dark pycnidia embedded in lesions but no erupting spore masses", "sign_b": "Distinct raised, volcano-like uredinia (pustules) that rupture to release tan to cinnamon-brown urediniospores; a sheet of paper tapped under the leaf collects spore dust", "shared": "Small (1-5 mm) lesions on soybean leaflets, first appearing in the lower/inner canopy, often beginning at or after flowering, capable of progressing upward and triggering premature yellowing and defoliation under favorable warm, wet conditions."}, {"pair_id": "soybean__septoria-leaf-spot__soybean-vein-necrosis-virus", "crop": "Soybean", "a": "Septoria Leaf Spot", "b": "Soybean Vein Necrosis Virus", "sign_a": "Tiny dark pinpoint pycnidia visible within the tan lesion centers under a hand lens; fungal sign present", "sign_b": "No fruiting bodies, no mold, no spores \u2014 viral disease with NO pathogen sign on the leaf; thrips (vector) may be present", "shared": "Irregular brown/rusty-brown necrotic patches on trifoliate leaves, often starting in the lower canopy, with surrounding yellowing and the potential for premature leaf drop during R-stage reproductive growth."}, {"pair_id": "soybean__southern-blight__taproot-decline-on-soybean", "crop": "Soybean", "a": "Southern Blight", "b": "Taproot Decline On Soybean", "sign_a": "Taproot interior largely normal; signs are EXTERNAL (mat plus sclerotia) at the crown; no charcoal-black staining of the taproot vascular/cortical tissue", "sign_b": "Taproot surface shows darkened charcoal-black thin stromatic tissue with white cottony mycelium inside the pith/cortex when split", "shared": "Scattered wilting, yellowing, and dying soybean plants appearing in patches within a row, often from mid-season onward, with white fungal mycelium found at or below the soil line and dark/blackened fungal structures on or in the lower stem and roots. Both are warm-climate, southern-US soilborne fungal diseases that can kill plants outright."}, {"pair_id": "spinach__downy-mildew__white-rust", "crop": "Spinach", "a": "Downy Mildew", "b": "White Rust", "sign_a": "Grayish-violet to purplish, fuzzy/cottony downy mold (sporangiophores) coating the underside; smears when rubbed", "sign_b": "Raised, smooth, glistening white-to-creamy blister-like pustules (sori) that are firm and later rupture to shed white powdery spores", "shared": "Cool-season foliar disease producing chlorotic/pale-yellow patches on the upper leaf surface (often angular and vein-delimited), with sporulation or pustules on the corresponding lower surface. Both spread under cool temperatures, high humidity, leaf wetness, and dense canopies; both can cause leaf distortion and render leaves unmarketable for fresh/processing spinach."}, {"pair_id": "squash__anthracnose__cucurbit-downy-mildew", "crop": "Squash", "a": "Anthracnose", "b": "Cucurbit Downy Mildew", "sign_a": "Anthracnose shows salmon-to-pink, sticky spore masses (acervuli, often with dark setae under a hand lens) on lesions of leaves, stems, or fruit.", "sign_b": "Downy mildew shows a fuzzy gray-to-purple/violet downy growth (sporangiophores) on the LOWER leaf surface directly beneath the angular yellow spots.", "shared": "Yellowish to tan foliar lesions on mature leaves during warm, humid weather, often beginning on older/lower leaves and capable of coalescing into large necrotic areas with rapid defoliation. Both are favored by leaf wetness and can look angular early, leading to confusion in the field."}, {"pair_id": "squash__anthracnose__gummy-stem-blight", "crop": "Squash", "a": "Anthracnose", "b": "Gummy Stem Blight", "sign_a": "Stem lesions are elongate, dry, sunken and tan with little or no ooze; girdling is uncommon and secondary to foliar/fruit damage", "sign_b": "Stem shows a water-soaked-to-tan canker at nodes or crown that cracks and exudes a reddish-brown to amber gummy beads (the gummy exudate that names the disease)", "shared": "Circular-to-angular tan/brown necrotic leaf spots, sometimes with concentric zonation and yellow halos, that coalesce and blight foliage; lesions also appear on petioles, stems, and developing fruit; both favor warm temperatures and prolonged leaf wetness or high humidity."}, {"pair_id": "squash__anthracnose__phytophthora-blight", "crop": "Squash", "a": "Anthracnose", "b": "Phytophthora Blight", "sign_a": "Salmon-to-pink slimy spore masses (acervuli) oozing in concentric rings within sunken lesions", "sign_b": "Dense white cottony/fuzzy growth (sporangia) coating the lesion surface, especially on fruit", "shared": "On squash, both produce expanding necrotic-to-water-soaked lesions on leaves and fruit, can cause defoliation, and lead to fruit rot in warm, wet weather, especially mid-to-late season after rain or overhead irrigation. Both spread by splashing water and favor humid canopies."}, {"pair_id": "squash__cucurbit-downy-mildew__gummy-stem-blight", "crop": "Squash", "a": "Cucurbit Downy Mildew", "b": "Gummy Stem Blight", "sign_a": "No stem canker and no gum; the pathogen is an obligate biotroph restricted to living leaf tissue with downy sporulation only", "sign_b": "Tan-to-dark stem/crown canker that oozes amber-brown gummy droplets and is studded with black pycnidia/perithecia\u2014diagnostic", "shared": "Yellow-to-brown angular or irregular leaf spots that coalesce, leading to leaf scorching and defoliation under warm, wet, humid conditions; both reduce canopy and yield and appear mid-to-late season."}, {"pair_id": "squash__cucurbit-downy-mildew__phytophthora-blight", "crop": "Squash", "a": "Cucurbit Downy Mildew", "b": "Phytophthora Blight", "sign_a": "Downy gray-to-purple sporulation on the undersides of vein-bounded lesions.", "sign_b": "White cottony growth on fruit/crown with soft, watery rot.", "shared": "Water-soaked, blighted foliage with rapid decline of the plant."}, {"pair_id": "squash__cucurbit-downy-mildew__powdery-mildew", "crop": "Squash", "a": "Cucurbit Downy Mildew", "b": "Powdery Mildew", "sign_a": "Fine grey-to-purplish-brown downy fuzz (sporangiophores) confined to the underside beneath each angular lesion", "sign_b": "No undersurface fuzz; instead a white-to-tan powdery growth that wipes off, present on BOTH leaf surfaces and petioles", "shared": "Yellow to chlorotic patches on the upper surface of older/lower leaves first, progressing upward through the canopy. Both cause loss of leaf function, premature senescence, defoliation, and reduced fruit quality/sunscald exposure. Both favor dense canopies and are most damaging from mid-season onward on cucurbits including squash."}, {"pair_id": "squash__gummy-stem-blight__phytophthora-blight", "crop": "Squash", "a": "Gummy Stem Blight", "b": "Phytophthora Blight", "sign_a": "Tiny black raised dots (pycnidia/perithecia) embedded in lesions, releasing a creamy spore mass; amber gummy droplets present", "sign_b": "White, dense, cottony sporangial growth (visible mold) on fruit and lesion surfaces under humid conditions; no black pycnidia, no gum", "shared": "Wilting, collapsing squash vines with darkened, girdling lesions at the crown or along the stem, plus rotting fruit. Both can show water-soaked tissue, defoliation, and plant death, often appearing in patches in the field during warm, wet weather."}, {"pair_id": "squash__phytophthora-blight__plectosphaerella-fungus", "crop": "Squash", "a": "Phytophthora Blight", "b": "Plectosphaerella Fungus", "sign_a": "Abundant dense white, powdery-sugar-like sporulation (sporangia of an oomycete) coats infected crown and fruit", "sign_b": "No white powdery oomycete bloom; at most sparse pale/cream fungal growth, with diagnosis requiring culture/microscopy of acervuli and slimy conidial masses", "shared": "A squash plant that wilts and collapses associated with rot at the soil line. Both cause crown/collar/root rot, water-soaked-to-brown basal tissue, vascular discoloration, and eventual death of the vine, and both originate from soilborne inoculum."}, {"pair_id": "strawberry__angular-leaf-spot-of-strawberry__gray-mold", "crop": "Strawberry", "a": "Angular Leaf Spot Of Strawberry", "b": "Gray Mold", "sign_a": "Viscous, glistening bacterial ooze (exudate) on the lower leaf surface that dries to a whitish scaly/varnished film; NO fuzzy growth", "sign_b": "Abundant fuzzy gray-brown mold (conidiophores/spores) covering rotted flowers and fruit, dusty when disturbed", "shared": "Dark, water-soaked or browning lesions appearing on strawberry foliage and fruit/calyx during cool, wet, humid spring weather; both spread by splashing water/overhead irrigation and can cause tissue collapse, leading growers to attribute general \"wet-weather rot and spotting\" to a single cause."}, {"pair_id": "strawberry__anthracnose__gray-mold", "crop": "Strawberry", "a": "Anthracnose", "b": "Gray Mold", "sign_a": "Salmon-pink to orange, gelatinous/slimy spore masses (acervuli), sometimes with dark setae; never gray fuzz", "sign_b": "Abundant gray-to-tan fuzzy mold (mycelium with grape-like conidial clusters); no pink slime", "shared": "Soft-to-firm rotting of flowers and ripening/ripe fruit with sunken, discolored lesions that expand rapidly in warm humid weather; both can cause blossom blight, fruit mummification, and rapid post-harvest losses, and both spread by splashing rain/overhead irrigation and handling."}, {"pair_id": "strawberry__anthracnose__phomopsis-leaf-blight-and-fruit-rot", "crop": "Strawberry", "a": "Anthracnose", "b": "Phomopsis Leaf Blight And Fruit Rot", "sign_a": "Acervuli with hyaline, one-celled, curved-to-cylindrical conidia (often with setae); salmon/pink spore masses; Colletotrichum", "sign_b": "Pycnidia producing two spore types: hyaline fusiform alpha-conidia and long filiform/curved beta-conidia; Phomopsis (Phomopsis obscurans)", "shared": "Dark, sunken or discolored lesions that can appear on fruit during warm, humid weather, accompanied by small dark fruiting bodies and the potential for fruit rot and yield loss. Both spread by splashing rain/overhead irrigation and overwinter in plant debris."}, {"pair_id": "strawberry__gray-mold__ramularia-grevilleana-verkley---u--braun", "crop": "Strawberry", "a": "Gray Mold", "b": "Ramularia Grevilleana Verkley & U. Braun", "sign_a": "Abundant fuzzy, dusty GRAY mold (mycelium plus grape-like clusters of conidiophores) coating the rotted surface, easily dislodged as a smoky puff", "sign_b": "Sparse whitish tufts of conidiophores emerging mainly from leaf-spot centers/lower surface; not a thick gray fuzzy mat over rotted flesh", "shared": "On strawberry, both can appear as light/gray to whitish lesions on leaf tissue, petals, or senescing plant parts under cool, wet conditions, and both sporulate to produce a pale fuzzy or powdery look that draws the eye. In humid weather either can be found colonizing weakened or dying foliage and flower parts, giving overlapping initial impressions of a \"spotty leaf with grayish growth.\""}, {"pair_id": "strawberry__phomopsis-leaf-blight-and-fruit-rot__ramularia-grevilleana-verkley---u--braun", "crop": "Strawberry", "a": "Phomopsis Leaf Blight And Fruit Rot", "b": "Ramularia Grevilleana Verkley & U. Braun", "sign_a": "Dark, sunken, flask-shaped pycnidia (black pinpoint dots) embedded in the necrotic tissue, exuding cirrhi of two-celled alpha conidia in wet weather", "sign_b": "No pycnidia; instead delicate white-to-grayish tufts of erect conidiophores bearing chains of hyaline cylindrical Ramularia conidia on the lesion surface (mealy/frosty bloom), especially on the underside", "shared": "Discrete reddish-purple-bordered spots on mature/older strawberry leaves during warm, humid mid-to-late season, often on the same planting; both can cause leaf necrosis and reduce vigor, and both overwinter on infected leaf debris and old leaves."}, {"pair_id": "sweet-potato__black-rot__fusarium-wilt", "crop": "Sweet Potato", "a": "Black Rot", "b": "Fusarium Wilt", "sign_a": "Greenish-black to gray-black rot of storage-root flesh, often with a bitter taste; rot is a tissue rot, not confined to vascular strands.", "sign_b": "Brown to black discoloration of the vascular ring/strands within the stem and root, with surrounding flesh staying relatively firm and pale (vascular streaking).", "shared": "Stunted, off-color, wilting plants in the field with poor stands; internal darkening of vascular or storage tissue; reduced yield and unmarketable roots; both can be carried on infected slips/seed roots and persist in soil, causing patchy decline within a planting."}, {"pair_id": "sweet-potato__black-rot__java-black-rot", "crop": "Sweet Potato", "a": "Black Rot", "b": "Java Black Rot", "sign_a": "Black Rot produces grayish mycelium with erect, dark, long-necked perithecia bearing hat-shaped (galeate) ascospores, often with a gray fuzzy aspect and a fruity odor", "sign_b": "Java Black Rot produces black, carbonaceous pycnidia and dark mycelium, with mature dark, septate, longitudinally striate two-celled conidia", "shared": "Dark brown to black, firm, sunken lesions on storage roots that enlarge during storage and transit. Both rots can show black surface structures (signs) on aging lesions, both spread root-to-root in storage, both are favored by wounding at harvest, and both can render roots inedible with a bitter or off taste. Field-to-storage carryover and warm temperatures aggravate both."}, {"pair_id": "sweet-potato__black-rot__rhizopus-soft-rots", "crop": "Sweet Potato", "a": "Black Rot", "b": "Rhizopus Soft Rots", "sign_a": "Dark, gray-black lesion with concentric zonation; later fine dark fungal stroma and long-necked perithecia (flask-shaped fruiting bodies) producing sticky spore masses; no coarse whiskers", "sign_b": "Coarse, whiskery gray-to-black mold with visible pinhead sporangia (black dots on white-gray stalks), like bread mold, often bridging between roots", "shared": "Decaying sweet potato storage roots, often appearing during or after curing/storage, with darkening tissue and a soft or rotted feel to the affected root, leading growers to report generic \"root rot in storage.\""}, {"pair_id": "sweet-potato__black-rot__scurf", "crop": "Sweet Potato", "a": "Black Rot", "b": "Scurf", "sign_a": "Cut reveals brown to greenish-black necrotic flesh penetrating below the lesion \u2014 internal decay confirms Black Rot", "sign_b": "Cut reveals clean, normal white/orange flesh directly beneath the dark skin \u2014 discoloration is only skin-deep, confirming Scurf", "shared": "Dark to brownish-black discoloration on the periderm (skin) of sweet potato storage roots, most apparent after harvest, washing, curing, or in storage; both degrade the cosmetic appearance and marketability of the root and both are favored by warm, moist soil/storage conditions and can be carried on infected seed roots/slips and contaminated soil."}, {"pair_id": "sweet-potato__fusarium-wilt__southern-blight", "crop": "Sweet Potato", "a": "Fusarium Wilt", "b": "Southern Blight", "sign_a": "Internal vascular tissue (the ring of strands) is stained brown to black, running up the stem; no external mat of growth.", "sign_b": "A white, fan-like cottony mycelial mat coats the stem surface at the soil line, often bearing tan-brown mustard-seed-sized sclerotia; internal vascular ring stays clean.", "shared": "Scattered or patchy wilting and yellowing of vines, stunting, and decline that may progress to plant death; both show damage concentrated at the stem base/soil line and can rot fleshy roots in storage or in the field, mimicking a generic \"wilt and rot\" complex."}, {"pair_id": "sweet-potato__java-black-rot__rhizopus-soft-rots", "crop": "Sweet Potato", "a": "Java Black Rot", "b": "Rhizopus Soft Rots", "sign_a": "Black, embedded pycnidia (pimple-like fruiting bodies) in dark stromatic tissue; thin gray-to-black mycelium, NO tall pin-heads", "sign_b": "Coarse gray-white whiskery aerial mycelium bearing black sporangial 'pinheads' (Rhizopus 'whiskers') spanning root to root", "shared": "Postharvest decay of harvested sweet potato storage roots, typically entering through wounds, cut/broken ends, or bruises sustained at digging or handling. Affected roots show softening, internal discoloration, and external decay during curing, storage, or transit, often spreading root-to-root in the bin."}, {"pair_id": "sweet-potato__southern-blight__streptomyces-soil-rot", "crop": "Sweet Potato", "a": "Southern Blight", "b": "Streptomyces Soil Rot", "sign_a": "Conspicuous white cottony mycelial fans and round 1-3 mm tan/brown sclerotia (resembling mustard seeds) on stem and adjacent soil/debris", "sign_b": "No aerial mycelium and no sclerotia; only sunken corky pits and lesions on root surfaces", "shared": "Stunted, wilting or yellowing plants in patches within a warm sweet potato field, with decay at or below the soil line and reduced/deformed storage root yield. Both can produce sunken, rotted tissue and are favored by warm soils, leading a grower to call either one a \"soil rot.\""}, {"pair_id": "tomato__anthracnose__septoria-leaf-spot", "crop": "Tomato", "a": "Anthracnose", "b": "Septoria Leaf Spot", "sign_a": "Concentric sunken fruit lesions oozing salmon-pink spore masses (acervuli).", "sign_b": "Small tan leaf spots with dark margins and tiny black pycnidia speckling the center.", "shared": "Small dark leaf spots, some bearing tiny dark specks in the center."}, {"pair_id": "tomato__bacterial-canker-and-wilt-of-tomato__bacterial-speck-of-tomato", "crop": "Tomato", "a": "Bacterial Canker And Wilt Of Tomato", "b": "Bacterial Speck Of Tomato", "sign_a": "Yellow-to-reddish-brown vascular discoloration, mealy/disintegrating pith, internal cavities, and creamy bacterial ooze from the cut xylem (Clavibacter is systemic in the xylem)", "sign_b": "Clean white vascular tissue with no discoloration, no cankers, no ooze (Pseudomonas speck never invades the vascular system)", "shared": "Small dark brown-to-black necrotic leaf lesions, leaflet marginal scorching, foliar blighting, and fruit blemishes; both favored by cool wet weather and overhead irrigation, both seedborne and spread by water splash, and both can cause early-season leaf flecking that mimics the other."}, {"pair_id": "tomato__bacterial-canker-and-wilt-of-tomato__bacterial-wilt", "crop": "Tomato", "a": "Bacterial Canker And Wilt Of Tomato", "b": "Bacterial Wilt", "sign_a": "No spontaneous milky ooze stream from a stem in water; vascular browning present but the streaming test is negative (Clavibacter is Gram-positive, does not stream this way)", "sign_b": "Within minutes a thread of milky-white bacterial ooze flows from the cut vascular bundles into the water (positive Ralstonia streaming test)", "shared": "Wilting tomato plants, often during fruiting, with browning/discoloration of the internal vascular tissue when the stem is cut. Both can kill plants and both spread in warm conditions, so a generic \"wilting plant with stained vascular ring\" looks identical at first glance."}, {"pair_id": "tomato__bacterial-canker-and-wilt-of-tomato__early-blight", "crop": "Tomato", "a": "Bacterial Canker And Wilt Of Tomato", "b": "Early Blight", "sign_a": "Brown, yellow, or reddish discolored vascular ring; pith may be mealy/cavitated; cloudy bacterial ooze (positive stream test) from cut stem", "sign_b": "Vascular tissue stays clean/white-green; no ooze; if incubated in moist chamber, dark velvety fungal sporulation forms on leaf lesions", "shared": "Lower and mid-canopy leaves develop brown necrotic areas with marginal/interveinal browning and yellowing, leaflets curl and die, and the plant looks progressively scorched from the bottom up. Both can appear in warm humid weather on staked field or tunnel tomatoes and lead to defoliation and reduced yield."}, {"pair_id": "tomato__bacterial-canker-and-wilt-of-tomato__phytophthora-blight", "crop": "Tomato", "a": "Bacterial Canker And Wilt Of Tomato", "b": "Phytophthora Blight", "sign_a": "Yellow-to-brown discoloration of the vascular ring, often with a mealy/creamy yellow pith breakdown and cream-colored bacterial ooze/streaming from cut vessels; cavities in pith", "sign_b": "Brown, water-soaked cortical/crown rot with NO bacterial streaming; chocolate-brown firm-to-mushy decay; under moisture, white cottony mycelium and oospores microscopically", "shared": "Wilting and decline of tomato plants, often progressing to death; stem lesions/discoloration and a generally water-soaked, deteriorating appearance of affected tissue. Both can show wilting that starts on part of the plant and spreads, and both can produce stem cankers or rot that compromise the vascular/structural integrity of the plant."}, {"pair_id": "tomato__bacterial-canker-and-wilt-of-tomato__southern-bacterial-wilt", "crop": "Tomato", "a": "Bacterial Canker And Wilt Of Tomato", "b": "Southern Bacterial Wilt", "sign_a": "No spontaneous milky streaming; xylem yellow-brown but does not exude a self-streaming bacterial plume (Clavibacter is Gram-positive, ooze test negative)", "sign_b": "Cut stem suspended in water releases a spontaneous milky-white bacterial stream/ooze within minutes (positive Ralstonia streaming test)", "shared": "Wilting tomato plants with vascular (xylem) discoloration visible when the stem is cut, leading to decline and death. Both can show stunting and yellowing, and both produce brown-to-tan streaking in the vascular ring of the lower stem."}, {"pair_id": "tomato__bacterial-speck-of-tomato__early-blight", "crop": "Tomato", "a": "Bacterial Speck Of Tomato", "b": "Early Blight", "sign_a": "Tiny pinpoint specks, mostly 1-3 mm, dark brown to black, never developing concentric rings", "sign_b": "Larger lesions 6-12 mm or more with concentric dark rings forming a target-board / bullseye pattern", "shared": "Dark brown-to-black necrotic spots on tomato leaflets, often with surrounding yellowing, that develop during cool-to-warm wet weather and can be mistaken for one another in early stages; both may also blemish fruit."}, {"pair_id": "tomato__bacterial-speck-of-tomato__septoria-leaf-spot", "crop": "Tomato", "a": "Bacterial Speck Of Tomato", "b": "Septoria Leaf Spot", "sign_a": "No fungal fruiting bodies; lesions are bacterial with no pycnidia. A bacterial streaming test (lesion in water) shows cloudy ooze; surface specks lack embedded structures.", "sign_b": "Tan/gray spot centers contain numerous pinpoint black pycnidia (visible as dark dots in the lesion center under a hand lens), often exuding pale cirrhi when wet.", "shared": "Many small (1-3 mm) dark brown to black necrotic spots scattered across leaflets, often most abundant on lower/older foliage, favored by cool to moderate temperatures with leaf wetness, with chlorotic yellowing and leaf drop as spots coalesce."}, {"pair_id": "tomato__bacterial-speck-of-tomato__tomato-spotted-wilt-virus", "crop": "Tomato", "a": "Bacterial Speck Of Tomato", "b": "Tomato Spotted Wilt Virus", "sign_a": "Crushed lesion under microscope shows bacterial streaming/ooze; lesions test positive for P. syringae (Pst), no virus detected", "sign_b": "No bacterial ooze; immunostrip/ELISA/RT-PCR is positive for Tomato spotted wilt virus, confirming systemic Tospovirus", "shared": "Small dark brown-to-black spots and necrotic flecks on tomato leaves, sometimes with surrounding yellowing, plus blemishes on green fruit, leading growers to confuse the two early in the season."}, {"pair_id": "tomato__bacterial-wilt__sclerotinia-timber-rot", "crop": "Tomato", "a": "Bacterial Wilt", "b": "Sclerotinia Timber Rot", "sign_a": "Browned, water-soaked vascular tissue that exudes a viscous milky-white bacterial stream; a cut stem suspended in clear water releases threads of ooze", "sign_b": "White cottony mycelium lining a hollowed pith with hard black seed-like sclerotia inside the stem", "shared": "Mature tomato plants showing wilting that progresses to collapse and death, often with discoloration or lesions on the lower-to-mid stem and a generally healthy-looking root system at first glance."}, {"pair_id": "tomato__bacterial-wilt__southern-blight", "crop": "Tomato", "a": "Bacterial Wilt", "b": "Southern Blight", "sign_a": "No fungal growth; no sclerotia. Stem surface is clean (bacterial pathogen, no visible signs)", "sign_b": "White fan-like mycelial mat on the lower stem/soil surface bearing tan-to-reddish-brown, mustard-seed-sized round sclerotia", "shared": "A vigorous mid-season tomato plant wilts abruptly during hot, humid weather, frequently with foliage still green at first collapse, and the problem originates at the soil line / lower stem and roots rather than as a foliar leaf-spot progression."}, {"pair_id": "tomato__bacterial-wilt__verticillium-wilts", "crop": "Tomato", "a": "Bacterial Wilt", "b": "Verticillium Wilts", "sign_a": "Spontaneous milky-white bacterial streaming threads flow from the cut vascular tissue within minutes (positive ooze test)", "sign_b": "No bacterial streaming; water stays clear (diagnosis requires culturing/microscopy for fungal microsclerotia/conidia)", "shared": "A tomato plant showing wilting foliage with reduced vigor, plus brown discoloration of the internal vascular tissue when the stem is cut, leading to confusion between a bacterial vascular pathogen and a fungal vascular pathogen."}, {"pair_id": "tomato__early-blight__late-blight", "crop": "Tomato", "a": "Early Blight", "b": "Late Blight", "sign_a": "No white fuzzy growth; lesions stay dry and the dark concentric rings are the diagnostic feature (Alternaria conidia are dark and not visible as bloom).", "sign_b": "Delicate white-to-grayish downy/fuzzy mold (sporangia) at the lesion margin on the leaf underside, visible under high humidity, sometimes ringing the lesion.", "shared": "Dark brown to black necrotic lesions on tomato foliage with progressive blighting and defoliation; lesions can also affect stems and fruit, and severe cases collapse the canopy from the bottom up or rapidly throughout, leading growers to call both simply \"blight.\""}, {"pair_id": "tomato__early-blight__septoria-leaf-spot", "crop": "Tomato", "a": "Early Blight", "b": "Septoria Leaf Spot", "sign_a": "No pinpoint black dots; dark velvety sporulation may be visible but no embedded pycnidia", "sign_b": "Tiny black pinpoint pycnidia (fruiting bodies) embedded in the pale lesion center", "shared": "Lower/older leaves develop brown necrotic spots surrounded by yellow halos, leading to leaf chlorosis and defoliation that advances upward. Both favor warm temperatures, prolonged leaf wetness, overhead irrigation, and crowded canopies, and both overwinter in crop debris. Early-season scouting often shows scattered small dark spots on bottom foliage that look nearly identical."}, {"pair_id": "tomato__early-blight__tomato-leaf-mould", "crop": "Tomato", "a": "Early Blight", "b": "Tomato Leaf Mould", "sign_a": "No fuzzy growth on underside; lesions necrotic on both faces, may show dark sporulation but no felty mold layer", "sign_b": "Distinctive olive-green to grayish-brown velvety/felty mold (sporulation) on the underside directly beneath the yellow upper-surface blotch", "shared": "Yellow blotches and necrotic patches on tomato leaves, beginning on older lower foliage, progressing upward, with eventual chlorosis, leaf death, and defoliation; both favored by extended leaf wetness and humidity."}, {"pair_id": "tomato__early-blight__tomato-spotted-wilt-virus", "crop": "Tomato", "a": "Early Blight", "b": "Tomato Spotted Wilt Virus", "sign_a": "Distinct 'target-board' concentric dark rings on leaf spots with olive-to-black velvety sporulation; lesions discrete on leaflets, often surrounded by a yellow halo", "sign_b": "No fungal sporulation; instead bronze/purplish cast, distorted growth, and presence of thrips (vector); often one-sided or systemic pattern through the plant", "shared": "Dark brown to black foliar spots, some with concentric ring patterns; leaf yellowing/bronzing progressing to necrosis and defoliation; necrotic flecking; and necrotic/ringed lesions on green-to-ripe fruit. General decline and reduced vigor occur in both."}, {"pair_id": "tomato__early-blight__verticillium-wilts", "crop": "Tomato", "a": "Early Blight", "b": "Verticillium Wilts", "sign_a": "Vascular (xylem) tissue is clean and white/green; no internal browning", "sign_b": "Tan-to-brown vascular streaking in the xylem of the lower stem and roots (vascular discoloration)", "shared": "Yellowing and browning that begins on the oldest, lowest leaves and advances up the plant during fruit development, often with partial defoliation, reduced vigor, and sun-exposed fruit. Both are favored by stressed plants and can appear mid- to late-season, leading to a generic \"the bottom of my tomatoes is dying\" complaint."}, {"pair_id": "tomato__gray-mold__late-blight", "crop": "Tomato", "a": "Gray Mold", "b": "Late Blight", "sign_a": "Abundant dusty GRAY-BROWN fuzzy mold (conidiophores) that puffs out as a smoky cloud when disturbed; grows on dead/necrotic tissue surface, often on stems and old lesions", "sign_b": "Fine WHITE downy fuzz (sporangiophores) confined to the lesion margin / undersurface of leaf and fruit, appearing in a delicate band where living meets dead tissue, only under high humidity", "shared": "Rapidly enlarging brown necrotic lesions on leaves, stems, and fruit during cool, humid, wet weather; both can show a visible fuzzy/moldy growth on affected tissue and can cause collapse of foliage and fruit rot, especially in greenhouses or during prolonged leaf-wetness periods."}, {"pair_id": "tomato__gray-mold__phytophthora-blight", "crop": "Tomato", "a": "Gray Mold", "b": "Phytophthora Blight", "sign_a": "Dense fuzzy GRAY-to-tan velvety mold (conidiophores) coating the lesion, dusty when disturbed", "sign_b": "Sparse WHITE cottony/downy mycelium (sporangia) on the surface, never gray and dusty", "shared": "Soft, water-soaked, rapidly expanding rot of fruit and lower stem/foliage in humid, wet conditions; affected tissue collapses and plants may wilt, with overlapping crop-loss patterns in dense, poorly ventilated tomato plantings."}, {"pair_id": "tomato__gray-mold__rhizopus-soft-rots", "crop": "Tomato", "a": "Gray Mold", "b": "Rhizopus Soft Rots", "sign_a": "Dense gray to gray-brown velvety/dusty mold (botrytis = 'bunch of grapes'); short branched conidiophores bearing clustered grape-like spore heads; tan-brown firm-watery rot beneath.", "sign_b": "Coarse, tall, fluffy whitish 'bread-mold' growth that turns gray-black, dotted with conspicuous black pinhead sporangia on tall stalks; underlying tissue liquefied and leaky.", "shared": "Soft, watery to mushy decay of mature/ripe or wounded tomato fruit, typically beginning at a wound or the stem scar, with surface collapse and an aerial fungal mold; common as a post-harvest / transit rot under warm, humid, poorly ventilated conditions."}, {"pair_id": "tomato__gray-mold__sclerotinia-timber-rot", "crop": "Tomato", "a": "Gray Mold", "b": "Sclerotinia Timber Rot", "sign_a": "No internal sclerotia; lesion surface develops a velvety GRAY-BROWN powdery mold (conidiophores) that releases dust clouds of spores when disturbed", "sign_b": "Stem interior is hollowed/shredded and packed with large (3-10 mm) hard, irregular BLACK sclerotia; surface mycelium is dense white cotton with no gray sporulation", "shared": "Light brown to tan, water-soaked cankers girdling the main stem (often at pruning wounds, leaf axils, or the soil line), wilting of foliage above the lesion, plant collapse, and white cottony mycelial growth on stems and rotting fruit under cool, humid conditions."}, {"pair_id": "tomato__gray-mold__tomato-leaf-mould", "crop": "Tomato", "a": "Gray Mold", "b": "Tomato Leaf Mould", "sign_a": "Botrytis produces a profuse gray-brown, dusty/fuzzy mold (conidiophores) on the surface of any decaying tissue regardless of leaf side; puffs of dust when disturbed.", "sign_b": "Fulvia produces a distinctive olive-green to grayish-brown velvety mold on the LOWER leaf surface directly beneath the yellow upper-surface spot.", "shared": "Foliar fungal growth on tomato under high humidity and free moisture, often in protected culture (greenhouse/high tunnel). Both can show a fuzzy or velvety mold layer and lead to leaf yellowing, decline, and defoliation, and both spread by airborne spores in dense, poorly ventilated canopies."}, {"pair_id": "tomato__late-blight__phytophthora-blight", "crop": "Tomato", "a": "Late Blight", "b": "Phytophthora Blight", "sign_a": "Stem stays internally sound at the crown; lesions are external aerial cankers higher up, no soil-line girdling rot", "sign_b": "Crown and lower stem show internal chocolate-brown cortical rot girdling the plant at/near the soil line, with collapse", "shared": "Dark brown to black, greasy water-soaked lesions that expand rapidly and can collapse tissue; both can rot tomato fruit; both favor wet conditions and free moisture; both produce a coenocytic Phytophthora mycelium and can cause sudden plant decline that alarms growers."}, {"pair_id": "tomato__late-blight__tomato-leaf-mould", "crop": "Tomato", "a": "Late Blight", "b": "Tomato Leaf Mould", "sign_a": "Sparse white, downy/cottony sporulation (sporangiophores) on the underside, typically at lesion margins, often fading by midday", "sign_b": "Dense, velvety olive-green to grayish-brown to purplish-brown felty mold patch directly beneath the yellow upper spot", "shared": "Irregular pale-green to yellowish blotches on the upper surface of leaves, often appearing first on older/lower foliage, with a fuzzy or felty growth developing on the corresponding lower leaf surface; both thrive under prolonged leaf wetness and high humidity and can cause leaf yellowing, necrosis, and defoliation."}, {"pair_id": "tomato__sclerotinia-timber-rot__southern-blight", "crop": "Tomato", "a": "Sclerotinia Timber Rot", "b": "Southern Blight", "sign_a": "Large (3-10+ mm), irregular, black, hard sclerotia forming INSIDE the hollow stem pith and on the lesion surface", "sign_b": "Small (0.5-2 mm), uniform, round, tan-to-reddish-brown sclerotia resembling mustard seeds, on the stem base and soil surface within the white mycelial mat", "shared": "Wilting, chlorosis and eventual collapse of an apparently healthy tomato plant; a girdling stem lesion bearing white, fluffy-to-felty mycelial growth; production of fungal sclerotia; favored by dense canopies and moisture; can kill plants outright and leave bleached, shredded stem tissue."}, {"pair_id": "tomato__sclerotinia-timber-rot__verticillium-wilts", "crop": "Tomato", "a": "Sclerotinia Timber Rot", "b": "Verticillium Wilts", "sign_a": "Fluffy white cottony mycelium on/around the lesion and hard black sclerotia (rat-dropping bodies) inside the pith/hollow stem", "sign_b": "No external mold and no sclerotia; no visible fungal structures on the surface", "shared": "Wilting and progressive decline of tomato plants, with branches or whole vines flagging, yellowing, and dying back. Both can affect mature/fruiting plants and lead to plant collapse, so from a distance both present as a \"wilting tomato.\""}, {"pair_id": "tomato__southern-bacterial-wilt__southern-blight", "crop": "Tomato", "a": "Southern Bacterial Wilt", "b": "Southern Blight", "sign_a": "No fungal growth; a cut stem section suspended in clear water exudes milky white bacterial streaming (ooze) within minutes from the cut vascular tissue", "sign_b": "Conspicuous white, fan-like (cottony) mycelium on the stem base and adjacent soil, bearing round tan-to-brown sclerotia the size of mustard seeds; no bacterial streaming", "shared": "Rapid, often unilateral-then-total wilting of an otherwise green tomato plant during hot, humid weather, with the lower stem/crown area showing discoloration or lesions at the soil line and eventual plant death."}, {"pair_id": "tomato__southern-bacterial-wilt__verticillium-wilts", "crop": "Tomato", "a": "Southern Bacterial Wilt", "b": "Verticillium Wilts", "sign_a": "Spontaneous milky-white bacterial ooze streams from the cut stem into the water within minutes (positive Ralstonia streaming test); cut surface may exude sticky bacterial slime", "sign_b": "No bacterial ooze or streaming; water stays clear because Verticillium is a fungus with no bacterial exudate", "shared": "A field or greenhouse tomato showing wilting of foliage and stunting, with brown discoloration visible in the vascular ring when the stem or root crown is cut. Lower leaves may yellow and the plant declines, leading to confusion between a bacterial and a fungal vascular wilt."}, {"pair_id": "tomato__southern-blight__verticillium-wilts", "crop": "Tomato", "a": "Southern Blight", "b": "Verticillium Wilts", "sign_a": "Conspicuous white, fan-like mycelial mat on the lower stem and adjacent soil/debris, with tan-to-reddish-brown round sclerotia the size of mustard seeds", "sign_b": "No surface mycelium and no sclerotia; no visible external fungal growth on the stem base", "shared": "A mid- to late-season tomato plant showing wilting, foliar yellowing, and progressive decline, often appearing to \"give up\" suddenly. Both can kill or severely stunt the plant, and casual inspection of the canopy alone does not distinguish a root/crown rot from a vascular wilt."}, {"pair_id": "tomato__tomato-spotted-wilt-virus__verticillium-wilts", "crop": "Tomato", "a": "Tomato Spotted Wilt Virus", "b": "Verticillium Wilts", "sign_a": "Vascular tissue clean/white; no internal browning (virus is systemic, not vascular-occluding in the way a fungus is)", "sign_b": "Distinct tan-to-brown vascular discoloration in the stem, visible as a ring or streaks when split", "shared": "Wilting, leaf yellowing/chlorosis, stunting, and overall plant decline on tomato. Both can show asymmetric or partial-plant symptoms and can be mistaken for water stress or generic root/vascular trouble. Neither shows obvious surface fungal growth on leaves."}, {"pair_id": "watermelon__anthracnose__bacterial-fruit-blotch", "crop": "Watermelon", "a": "Anthracnose", "b": "Bacterial Fruit Blotch", "sign_a": "Salmon-pink to orange gelatinous spore masses (conidia from acervuli), sometimes with tiny black setae, on the lesion surface in wet weather \u2014 a fungal sign.", "sign_b": "No fungal fruiting bodies; cut tissue placed in clear water streams cloudy bacterial ooze, and lesions exude bacteria rather than colored spore masses.", "shared": "Dark, depressed lesions on the upper surface of nearly mature fruit appearing in hot, humid, rainy conditions late in the season; both can begin as small spots that enlarge, both spread by rain splash and overhead irrigation, both are seedborne, and both can cause rapid pre/post-harvest fruit rot that confuses field scouts."}, {"pair_id": "watermelon__anthracnose__cucurbit-downy-mildew", "crop": "Watermelon", "a": "Anthracnose", "b": "Cucurbit Downy Mildew", "sign_a": "Salmon-colored to pinkish slimy spore masses (acervuli) ooze from lesion centers in wet weather; tiny black setae/dots in dry lesions", "sign_b": "Downy grayish-purple to dark fuzzy growth (sporangiophores) on the lower leaf surface beneath the angular yellow patches", "shared": "Yellow-to-brown foliar spots and blighting on watermelon leaves during warm, humid, wet weather; both spread rapidly under prolonged leaf wetness, both can defoliate vines from older leaves upward, and both first appear as small chlorotic flecks that enlarge and coalesce, causing field-scale loss of canopy and reduced fruit quality."}, {"pair_id": "watermelon__anthracnose__gummy-stem-blight", "crop": "Watermelon", "a": "Anthracnose", "b": "Gummy Stem Blight", "sign_a": "Acervuli producing salmon-pink to orange spore masses (conidial ooze) on lesions when wet; setae may be visible", "sign_b": "Pycnidia exuding a creamy-white to amber spore tendril (cirrhus); no pink spore mass", "shared": "Circular to irregular dark brown/tan necrotic leaf lesions that may coalesce and cause blighting; stem cankering; fruit rot; abundant tiny black fruiting bodies (acervuli vs pycnidia) embedded in lesion tissue; both spread by splashing water and warm humid weather and overwinter on crop debris and seed."}, {"pair_id": "watermelon__bacterial-fruit-blotch__gummy-stem-blight", "crop": "Watermelon", "a": "Bacterial Fruit Blotch", "b": "Gummy Stem Blight", "sign_a": "Milky bacterial streaming from a cut lesion in a water-mount; no fruiting bodies; cotyledon lesions ooze when crushed", "sign_b": "Tiny black pinpoint pycnidia (and sometimes pseudothecia) embedded in necrotic tissue; gummy ooze on stem cankers; no bacterial streaming", "shared": "Dark, water-soaked angular-to-irregular foliar lesions; problems traceable to infested seed and crowded, humid transplant greenhouses; cotyledon and seedling symptoms; and economically damaging rind/fruit lesions. Both spread in warm, wet, splashing-rain conditions and can cause stand loss in seedling trays."}, {"pair_id": "watermelon__bacterial-fruit-blotch__phytophthora-blight", "crop": "Watermelon", "a": "Bacterial Fruit Blotch", "b": "Phytophthora Blight", "sign_a": "Bacterial streaming/ooze (milky exudate from cut lesion in water); cracked rind with sticky amber bacterial ooze, NO mold", "sign_b": "White, cottony/powdery mold (sporangia) coating the rotting fruit surface in humid conditions", "shared": "Mid-to-late season collapse of watermelon with water-soaked, dark, rapidly enlarging lesions on the fruit during hot, humid, rainy periods; both can cause sudden fruit rot in the field and both are favored by overhead moisture and warm temperatures, leading growers to lump them as \"fruit rot / fruit blight.\""}, {"pair_id": "watermelon__cucurbit-downy-mildew__gummy-stem-blight", "crop": "Watermelon", "a": "Cucurbit Downy Mildew", "b": "Gummy Stem Blight", "sign_a": "A downy grayish-purple to dark fuzzy sporulation mat (sporangiophores) coats the lower lesion surface under leaf wetness/high humidity", "sign_b": "No downy growth; instead tiny black specks (pycnidia) are embedded within necrotic leaf tissue, visible on either surface with a hand lens", "shared": "Mid- to late-season watermelon plants with chlorotic-to-necrotic angular or irregular leaf lesions, leaf yellowing and blighting that can rapidly defoliate the canopy under warm, humid, wet conditions, leading to sunscald of exposed fruit and yield loss."}, {"pair_id": "watermelon__cucurbit-downy-mildew__phytophthora-blight", "crop": "Watermelon", "a": "Cucurbit Downy Mildew", "b": "Phytophthora Blight", "sign_a": "Fine grayish-purple, fuzzy downy growth (sporangiophores) on the lower leaf surface only, confined to lesions", "sign_b": "White, cottony/mealy mold of sporangia on any infected tissue including stems, crown, and fruit surfaces, especially fruit", "shared": "Sudden appearance of water-soaked, angular-to-irregular leaf lesions that brown and coalesce, causing rapid vine collapse and field-scale defoliation under warm, humid, rainy conditions. Both can produce abundant sporulation in high humidity and both spread explosively after storms, so the early field impression of \"vines dying fast after rain\" is essentially identical."}, {"pair_id": "watermelon__cucurbit-downy-mildew__powdery-mildew", "crop": "Watermelon", "a": "Cucurbit Downy Mildew", "b": "Powdery Mildew", "sign_a": "Fine gray-purple-to-black downy/fuzzy sporulation confined to the underside, restricted to angular yellow patches bounded by leaf veins", "sign_b": "White-to-grayish powdery, flour-like fungal growth that can be wiped off, present on BOTH leaf surfaces (and petioles/stems)", "shared": "Yellowing and chlorotic blotching of older/crown leaves that progresses upward through the canopy, leaf curling and eventual necrosis with premature defoliation that exposes fruit to sunburn. Both favor dense canopies and reduce yield, and both first draw attention as patches of off-color foliage."}, {"pair_id": "watermelon__gummy-stem-blight__phytophthora-blight", "crop": "Watermelon", "a": "Gummy Stem Blight", "b": "Phytophthora Blight", "sign_a": "Dry tan-to-brown stem cankers that exude amber gummy ooze.", "sign_b": "Soft, water-soaked watery rot of the crown and fruit.", "shared": "Vine blight with stem lesions and fruit rot, leading to collapse."}, {"pair_id": "watermelon__phytophthora-blight__pythium-diseases", "crop": "Watermelon", "a": "Phytophthora Blight", "b": "Pythium Diseases", "sign_a": "Phytophthora capsici: large, papillate (nipple-like), deciduous (caducous) sporangia borne on long pedicels; lemon-shaped, readily detaching and dispersing aerially", "sign_b": "Pythium spp.: non-papillate sporangia that are often filamentous, lobate, or globose and produce a vesicle in which zoospores form; sporangia are NOT caducous/aerially deciduous", "shared": "Sudden wilting, water-soaked soft rot, and white cottony growth on watermelon plants growing in wet, low spots after heavy rain or over-irrigation. Both can kill seedlings (damping-off) and rot the crown, roots, and fruit, especially where fruit contacts saturated soil."}, {"pair_id": "watermelon__powdery-mildew__unknown-virus", "crop": "Watermelon", "a": "Powdery Mildew", "b": "Unknown Virus", "sign_a": "White, talc-like powdery growth on leaf surfaces (especially undersides and older leaves) that rubs off with a finger; no causal arthropod sign needed", "sign_b": "No surface growth that rubs off; aphids, whiteflies, or cucumber beetles often present as vectors and symptoms are systemic within the tissue", "shared": "Yellowing, mottling/chlorosis and distortion of foliage with reduced vine vigor and potential fruit-quality decline. Both can appear mid-to-late season as patchy off-color leaves spreading through the planting, leading to confusion between a fungal foliar disease and a systemic virus."}, {"pair_id": "wheat__barley-yellow-dwarf-virus__fusarium-graminearum-schwabe", "crop": "Wheat", "a": "Barley Yellow Dwarf Virus", "b": "Fusarium Graminearum Schwabe", "sign_a": "No fungal growth anywhere; a virus produces no signs \u2014 only host discoloration and stunting; aphids may be present as vector", "sign_b": "Salmon-pink to orange sporodochia in the spikelet bracts/rachis (and blue-black perithecia later); pink-tinged shriveled 'tombstone' kernels", "shared": "Patchy stand discoloration and premature, uneven ripening/senescence of wheat \u2014 affected plants stand out as off-color (yellow/tan) against a green canopy, with reduced yield and shriveled grain."}, {"pair_id": "wheat__barley-yellow-dwarf-virus__fusarium-wilts--blights--rots-and-damping-off", "crop": "Wheat", "a": "Barley Yellow Dwarf Virus", "b": "Fusarium Wilts, Blights, Rots And Damping-Off", "sign_a": "Roots white and intact, crown and stem-base tissue clean and healthy internally \u2014 discoloration is only in leaves above ground", "sign_b": "Brown-to-honey discolored crown, rotted/pruned roots, and a characteristic browning of the subcrown internode and lower stem (vascular/cortical rot)", "shared": "Patchy, stunted, off-color wheat: yellow to reddish-purple foliage, reduced tillering, thin or dying stands, and premature whitening/death of tillers \u2014 symptoms that overlap during vegetative growth and into early reproductive stages."}, {"pair_id": "wheat__fusarium-wilts--blights--rots-and-damping-off__parastagonospora-nodorum", "crop": "Wheat", "a": "Fusarium Wilts, Blights, Rots And Damping-Off", "b": "Parastagonospora Nodorum", "sign_a": "Salmon-pink to orange sporodochia/mycelium in infected florets and at the rachis, sometimes with blue-black perithecia later", "sign_b": "Tiny dark-brown to black pycnidia embedded within the tan lesions on glumes and leaves, exuding cirri when wet", "shared": "On wheat heads both cause premature bleaching and discoloration of spikelets and glumes, and both are associated with shriveled, lightweight kernels and warm humid conditions during anthesis/grain fill, making spike symptoms look alike from a distance."}, {"pair_id": "wheat__parastagonospora-nodorum__tan-spot", "crop": "Wheat", "a": "Parastagonospora Nodorum", "b": "Tan Spot", "sign_a": "Lesions bear pycnidia \u2014 small embedded brown/black flask-shaped fruiting bodies that, when wet, exude cream-to-pinkish cirrhi of multicelled, slightly curved conidia; pycnidia are visible as tiny dots within the brown necrotic tissue.", "sign_b": "No pycnidia; instead dark conidiophores produce large cylindrical, multi-septate conidia with a snake-head basal cell, and the sexual stage forms black raised pseudothecia on residue. The center shows a dark conidial fleck rather than embedded pycnidia.", "shared": "Tan to brown foliar lesions on wheat leaves, each typically surrounded by a chlorotic yellow halo, beginning on lower/older leaves and progressing upward. Both diseases are residue-borne (overwinter on wheat stubble), spread by splash/wind during warm wet weather, and can cause premature leaf senescence and yield loss. In their early stages each forms small lens-shaped (lenticular) spots that enlarge and coalesce, and both are part of the septoria/tan-spot leaf-blotch complex frequently found together in the same field and even the same leaf."}, {"pair_id": "wheat__parastagonospora-nodorum__zymoseptoria-tritici", "crop": "Wheat", "a": "Parastagonospora Nodorum", "b": "Zymoseptoria Tritici", "sign_a": "Pycnidia are smaller, light to honey-brown, and ooze pinkish/cream cirrhi; conidia are short, hyaline with few (typically 1-3) septa", "sign_b": "Pycnidia are larger, dark brown to black, conspicuous in straw-colored lesions, and ooze whitish cirrhi; conidia are long, thread-like (filiform) with 3-7 septa", "shared": "Oval-to-lens-shaped tan/brown necrotic blotches on lower and mid-canopy leaves, often with a yellow (chlorotic) margin, coalescing under prolonged leaf wetness and progressing upward through the canopy; dark pycnidia embedded in dead tissue; both favored by cool-to-mild, wet/humid weather and dense stands, and both are residue-borne and rain-splash dispersed."}, {"pair_id": "wheat__powdery-mildew__stripe-rust", "crop": "Wheat", "a": "Powdery Mildew", "b": "Stripe Rust", "sign_a": "White to grayish-white cottony/powdery fungal colonies (mycelium + conidia) sitting ON the surface, easily wiped off leaving green tissue beneath", "sign_b": "Bright yellow to orange (rust-colored) powdery spores erupting FROM within the leaf, staining fingers yellow-orange", "shared": "Cool-season foliar disease of wheat presenting as discolored, raised material on leaf blades (often upper surface and lower/shaded canopy first), spreading upward through the canopy, capable of premature leaf senescence and yield loss under prolonged cool, moist conditions. Both leave powdery/dusty residue that rubs off onto fingers, and both can appear on leaf sheaths and occasionally glumes."}, {"pair_id": "wheat__powdery-mildew__zymoseptoria-tritici", "crop": "Wheat", "a": "Powdery Mildew", "b": "Zymoseptoria Tritici", "sign_a": "White-to-gray superficial powdery growth that wipes off.", "sign_b": "Tiny black pycnidia embedded in the dead blotches, visible as dark specks.", "shared": "Pale lower-canopy leaf lesions in a dense, moist wheat stand."}, {"pair_id": "wheat__stripe-rust__wheat-leaf-rust", "crop": "Wheat", "a": "Stripe Rust", "b": "Wheat Leaf Rust", "sign_a": "Yellow-orange uredinia arranged in narrow, dashed LINEAR STRIPES running parallel to the veins between the leaf veins", "sign_b": "Round-to-oval orange-brown uredinia SCATTERED randomly across the blade with no linear pattern", "shared": "Small, raised, powdery rust-colored pustules erupting through the leaf epidermis on wheat foliage during the growing season, shedding orange-to-yellow urediniospores onto fingers and clothing, with chlorosis around lesions and reduced photosynthetic area leading to yield loss."}, {"pair_id": "wheat__tan-spot__zymoseptoria-tritici", "crop": "Wheat", "a": "Tan Spot", "b": "Zymoseptoria Tritici", "sign_a": "No black pycnidia; sporulation is sparse dark conidiophores/conidia on the surface, no discrete embedded black dots", "sign_b": "Abundant tiny black pycnidia embedded in rows within the gray necrotic tissue, visible as pepper-grain dots that ooze cirrhi when wet", "shared": "Tan-to-brown elliptical/oval necrotic foliar lesions on wheat leaves, frequently surrounded by a yellow chlorotic halo, favored by extended leaf wetness and humid spring weather, both capable of progressing up the canopy from lower to upper leaves and reducing green leaf area and yield."}, {"pair_id": "wheat__wheat-leaf-rust__wheat-stem-rust", "crop": "Wheat", "a": "Wheat Leaf Rust", "b": "Wheat Stem Rust", "sign_a": "Pustules predominantly on the upper leaf blade surface; sheaths and stems largely spared", "sign_b": "Pustules concentrated on stems, leaf sheaths, and peduncles (and can occur on glumes/awns), not just leaf blades", "shared": "Reddish-brown to orange powdery uredinial pustules erupting through the epidermis of green wheat tissue, releasing rust-colored urediniospores that rub off on fingers/clothing. Both occur in spring through early summer, favor moist conditions and dew, and later in the season can form dark brown to black telia. Both can cause yield loss and appear during heading."}]

const SCHEMA = {
  type: 'object', additionalProperties: false,
  required: ['pair_id','farmer_lay_report','decisive_lay_a','decisive_lay_b','decisive_micro_a','decisive_micro_b'],
  properties: {
    pair_id: { type: 'string', description: 'echo exactly' },
    farmer_lay_report: { type: 'string', description: '1-2 sentences a grower would say about the visible problem; NO jargon; do NOT name either decisive sign' },
    decisive_lay_a: { type: 'string', description: "member_a's decisive sign in plain grower words" },
    decisive_lay_b: { type: 'string', description: "member_b's decisive sign in plain grower words" },
    decisive_micro_a: { type: 'boolean', description: 'true if A\'s decisive sign is microscopic / needs a hand lens or lab' },
    decisive_micro_b: { type: 'boolean' },
  },
}

function prompt(p) {
  return `You are a US extension plant pathologist writing LAY-LANGUAGE text a real farmer/grower would use. `
    + `Avoid all scientific terms: never say acervuli, pycnidia, sporulation, conidia, chlorosis, lesion, `
    + `mycelium, sori, uredinia. Say things like "pinkish ooze", "fuzzy growth", "yellowing", "raised bumps", `
    + `"powdery coating", "spots".\n\n`
    + `CROP: ${p.crop}\nMEMBER_A: ${p.a}  (decisive sign, technical: ${p.sign_a})\n`
    + `MEMBER_B: ${p.b}  (decisive sign, technical: ${p.sign_b})\nSHARED LOOK: ${p.shared}\n\n`
    + `Produce:\n`
    + `- farmer_lay_report: what the grower would say about what they SEE (the shared, ambiguous problem), `
    + `WITHOUT mentioning either decisive sign, so it could be either disease.\n`
    + `- decisive_lay_a / decisive_lay_b: each member's decisive sign translated to plain grower language `
    + `(what they would look for).\n`
    + `- decisive_micro_a / decisive_micro_b: true if that sign is microscopic or needs a hand lens / lab `
    + `(not visible to the naked eye in a normal field photo).\n`
    + `Set pair_id to exactly "${p.pair_id}". Return only the JSON object.`
}

const out = await parallel(PAIRS.map((p) => () =>
  agent(prompt(p), { label: `lay:${p.pair_id}`, phase: 'Lay', schema: SCHEMA }).catch(() => null)))
const results = out.filter(Boolean)
log(`lay-augmented ${results.length}/${PAIRS.length} graphs`)
return { n: results.length, results }
